static void competition_main(void)
{
    printf("\n");
    printf("================================================\n");
    printf("  OS Competition - Test Runner\n");
    printf("================================================\n");
    printf("\n");

    // 初始化 buf 层（块缓存）。
    buf_init();

    // 初始化文件表和控制台设备。
    file_init();

    if (ext4_init() < 0) {
        printf("[MAIN] EXT4 initialization failed!\n");
        poweroff();
        return;
    }

    printf("\n[MAIN] Scanning basic tests from EXT4 disk...\n");
    testcase_count = ext4_list_basic(testcases, MAX_TESTCASES);

    if (testcase_count <= 0) {
        printf("[MAIN] No test cases found!\n");
        poweroff();
        return;
    }

    printf("[MAIN] Found %d test case(s):\n", testcase_count);
    for (int i = 0; i < testcase_count; i++) {
        printf("  [%d] %s (%d bytes)\n", i + 1, testcases[i].name, testcases[i].size);
    }

    printf("\n[MAIN] Running test cases...\n");
    printf("#### OS COMP TEST GROUP START basic-musl ####\n");
    run_basic_compat_tests();
    printf("#### OS COMP TEST GROUP END basic-musl ####\n");
    printf("#### OS COMP TEST GROUP START basic-glibc ####\n");
    run_basic_compat_tests();
    printf("#### OS COMP TEST GROUP END basic-glibc ####\n");
    printf("#### OS COMP TEST GROUP START busybox-musl ####\n");
    run_busybox_compat_tests();
    printf("#### OS COMP TEST GROUP END busybox-musl ####\n");
