// 包装函数：调度器切换到这里时通常持有 myproc()->lk，必须先释放再进入主逻辑。
void competition_wrapper(void)
{
    // 调度器切换到这里时持有锁，必须释放
    spinlock_release(&myproc()->lk);

    competition_main();

    // 测试结束，关机
    printf("[MAIN] Competition finished, shutting down...\n");
    poweroff();
}

// 创建比赛 runner 进程：作为“用户进程的父进程”，统一加载/等待测试点。
void proc_make_competition(void)
{
    proc_t* p = proc_alloc();
    if (p == NULL) {
        panic("proc_make_competition: failed to allocate process");
    }

    // 第一个进程 pid 设为 0（便于调试与区分）。
    p->pid = 0;

    // 设置为全局第一个进程
    extern proc_t* proczero;
    proczero = p;

    // 设置上下文：ra 指向 competition_wrapper，sp 指向内核栈顶。
    p->ctx.ra = (uint64)competition_wrapper;
    p->ctx.sp = p->kstack + PGSIZE;

    // 设置为RUNNABLE
    p->state = RUNNABLE;

    // 释放alloc时持有的锁
    spinlock_release(&p->lk);

    printf("[proc] competition runner created (pid=%d), entry=0x%p\n", 
           p->pid, p->ctx.ra);
}

int main()
{
    // 使用原子变量确保只有第一个到达的 CPU 执行全局初始化。
    // OpenSBI 可能从任意 HART 启动。
    static volatile int first = 0;

    // 原子地尝试设置 first 为 1；若成功则是第一个 CPU。
    int is_first = __sync_lock_test_and_set(&first, 1) == 0;

    if(is_first) {
        // 第一个到达的 CPU 进行全局初始化。
        uart_init();
        print_init();
        printf("[main] CPU %d enters main and initializes system\n", r_tp());
        pmem_init();
        kvm_init();
        trap_kernel_init();
        trap_kernel_inithart();
        kvm_inithart();
        plic_init();
        plic_inithart();
        uart_init();
        virtio_disk_init();
        mmap_init();
        proc_init();
        // 注意：scheduler会开启中断，这里不需要显式开启
        // intr_on(); 
        proc_make_competition();
        __sync_synchronize();
        started = 1;
    } else {
        // 其它 CPU 等待全局初始化完成后执行每 hart 初始化。
        while(started == 0)
            ;
        __sync_synchronize();
        kvm_inithart();
        trap_kernel_inithart();
        plic_inithart();
    }

    printf("[main] CPU %d starting scheduler\r\n", r_tp());
    proc_scheduler();

    return 0;
}

/*
 * pmem.c - 物理内存分配器
 * 
 * 采用空闲链表管理物理页面，支持多核并发分配
 * 将内核和用户物理页分开管理，防止用户程序耗尽内核内存
 */

#include "mem/pmem.h"
#include "lib/lock.h"
#include "lib/print.h"
#include "lib/str.h"
#include "riscv.h"
#include "memlayout.h"

/*
 * ======== 数据结构定义 ========
 * 
 * 物理页链表节点：
 * 我们不需要额外的元数据来管理空闲页，而是直接利用空闲页本身的前8字节
 * 来存储指向下一个空闲页的指针。这样做的好处是零额外内存开销。
 * 
 * 示意图：
 *   +----------------+    +----------------+    +----------------+
 *   | next 指针 (8B) |    | next 指针 (8B) |    | next 指针 (8B) |
 *   | (剩余 4088B)   | -> | (剩余 4088B)   | -> | (剩余 4088B)   | -> NULL
 *   +----------------+    +----------------+    +----------------+
 *        page A               page B               page C
 */
typedef struct page_node {
    struct page_node* next;  // 指向下一个空闲页的指针
} page_node_t;

/*
 * 内存分配区域：
 * 包含该区域的起止地址、保护锁、可用页计数和空闲页链表头
 * 
 * 为什么要分开内核和用户区域？
 * 如果恶意用户程序不断申请内存不释放，可能耗尽所有物理页，
 * 导致内核无法工作。分开管理后，用户耗尽自己的配额不会影响内核。
 */
typedef struct alloc_region {
    uint64 begin;             // 区域起始物理地址
    uint64 end;               // 区域终止物理地址
    spinlock_t lk;            // 自旋锁，保护并发访问
    uint32 allocable;         // 当前可分配的页面数量
    page_node_t list_head;    // 链表头节点（本身不代表任何页，只是链表入口）
} alloc_region_t;

// 内核区域和用户区域分开管理
static alloc_region_t kern_region;  // 内核专用
static alloc_region_t user_region;  // 用户程序专用

/*
 * ======== 公开接口 ========
 */

/*
 * region_init - 初始化一个内存区域
 * 
 * @region: 要初始化的区域结构体
 * @name: 区域名称（用于调试）
 * @start: 起始地址
 * @end: 结束地址
 * 
 * 这个函数会：
 * 1. 设置区域的起止地址
 * 2. 初始化自旋锁
 * 3. 将区域内所有物理页加入空闲链表
 */
static void region_init(alloc_region_t *region, char *name, void *start, void *end)
{
    region->begin = (uint64)start;
    region->end = (uint64)end;
    region->allocable = 0;
    region->list_head.next = NULL;  // 链表初始为空

    spinlock_init(&region->lk, name);

    // 将起始地址向上对齐到页边界（4KB对齐）
    // 例如：0x80001234 向上对齐到 0x80002000
    char *p = (char*)PG_ROUND_UP((uint64)start);

    // 遍历所有完整的物理页，加入空闲链表
    for (; p + PGSIZE <= (char*)end; p += PGSIZE) {
        // 使用"头插法"将页面加入链表
        // 头插法：新节点插入链表头部，效率O(1)
        page_node_t *node = (page_node_t*)p;
        node->next = region->list_head.next;
        region->list_head.next = node;
        region->allocable++;
    }
}

/*
 * ======== 公开接口 ========
 */

/*
 * pmem_init - 初始化物理内存分配器
 * 
 * 内存布局：
 *   ALLOC_BEGIN                                           ALLOC_END
 *   |<-------- 内核区域 -------->|<-------- 用户区域 -------->|
 *   |     KERNEL_PAGES 个页      |          剩余页           |
 *   
 * 只在系统启动时由CPU 0调用一次
 */
void pmem_init(void)
{
    // 计算内核区域的结束地址
    uint64 kern_end = (uint64)ALLOC_BEGIN + KERNEL_PAGES * PGSIZE;

    // 确保内核区域不超过可用内存
    if (kern_end > (uint64)ALLOC_END) {
        kern_end = (uint64)ALLOC_END;
    }

    // 初始化内核区域
    region_init(&kern_region, "kern_pmem", ALLOC_BEGIN, (void*)kern_end);

    // 初始化用户区域（从内核区域结束到ALLOC_END）
    region_init(&user_region, "user_pmem", (void*)kern_end, ALLOC_END);

    printf("pmem: kern_region [%p - %p], %d pages\n", 
           kern_region.begin, kern_region.end, kern_region.allocable);
    printf("pmem: user_region [%p - %p], %d pages\n", 
           user_region.begin, user_region.end, user_region.allocable);
}

/*
 * pmem_alloc - 分配一个物理页
 * 
 * @in_kernel: true表示从内核区域分配，false表示从用户区域分配
 * @return: 分配的页地址，失败返回NULL
 * 
 * 分配过程（头移除）：
 *   分配前：list_head -> [page A] -> [page B] -> ...
 *   分配后：list_head -> [page B] -> ...
 *   返回：page A
 */
void* pmem_alloc(bool in_kernel)
{
    // 根据参数选择对应的区域
    alloc_region_t *region = in_kernel ? &kern_region : &user_region;

    // 获取锁，保护链表操作
    spinlock_acquire(&region->lk);

    // 从链表头取出一个空闲页
    page_node_t *page = region->list_head.next;

    if (page != NULL) {
        // 将链表头指向下一个节点（移除当前节点）
        region->list_head.next = page->next;
        region->allocable--;
    }

    spinlock_release(&region->lk);

    if (page != NULL) {
        // 将分配的页面清零，避免信息泄露和方便使用
        memset(page, 0, PGSIZE);
    }

    return (void*)page;
}

/*
 * pmem_free - 释放一个物理页
 * 
 * @page: 要释放的页地址
 * @in_kernel: true表示释放到内核区域，false表示释放到用户区域
 * 
 * 释放过程（头插入）：
 *   释放前：list_head -> [page B] -> [page C] -> ...
 *   释放后：list_head -> [page A] -> [page B] -> [page C] -> ...
 */
void pmem_free(uint64 page, bool in_kernel)
{
    // 根据参数选择对应的区域
    alloc_region_t *region = in_kernel ? &kern_region : &user_region;

    // 安全检查：确保地址是页对齐的（低12位必须为0）
    if ((page % PGSIZE) != 0) {
        panic("pmem_free: page not aligned");
    }

    // 安全检查：确保地址在对应区域范围内
    if (page < region->begin || page >= region->end) {
        panic("pmem_free: page out of region bounds");
    }

    // 填充垃圾数据（0x01重复），帮助检测释放后继续使用的bug
    memset((void*)page, 1, PGSIZE);

    // 获取锁
    spinlock_acquire(&region->lk);

    // 使用头插法将页面加回链表
    page_node_t *node = (page_node_t*)page;
    node->next = region->list_head.next;
    region->list_head.next = node;
    region->allocable++;

    spinlock_release(&region->lk);
}

/*
 * kvm.c - 内核页表（kernel virtual memory）
 *
 * 主要职责：
 *   - 提供通用的页表操作：vm_getpte/vm_mappages/vm_unmappages 等
 *   - 构建并激活内核页表 kernel_pagetable：映射设备寄存器、内核代码/数据、
 *     trampoline，以及每个进程的内核栈虚拟区间
 *
 * 说明：页表格式遵循 RISC-V Sv39。
 */

#include "riscv.h"
#include "memlayout.h"
#include "mem/vmem.h"
#include "mem/pmem.h"
#include "proc/proc.h"
#include "lib/print.h"
#include "lib/str.h"

// 内核页表
pgtbl_t kernel_pagetable;

// 来自kernel.ld，把内核内存分为两半，前面是代码（只读），后面是数据（可读写），这个变量就是分界线
extern char etext[];

// 来自trampoline.S，跳板页的物理地址
extern char trampoline[];


/*
 * vm_getpte - 获取虚拟地址对应的页表项
 * 
 * @pgtbl: 顶级页表
 * @va: 虚拟地址
 * @alloc: 是否创建不存在的中间页表
 * @return: PTE指针，失败返回NULL
 */
pte_t* vm_getpte(pgtbl_t pgtbl, uint64 va, bool alloc)
{
    if (va >= VA_MAX) {
        panic("vm_getpte: virtual address too large");
    }

    // 遍历三级页表 (level 2 -> level 1 -> level 0)
    for (int level = 2; level > 0; level--) {
        // 获取当前级别的页表索引
        uint64 index = VA_TO_VPN(va, level);
        pte_t *pte = &pgtbl[index];

        if (*pte & PTE_V) {
            // PTE有效，获取下一级页表
            pgtbl = (pgtbl_t)PTE_TO_PA(*pte);
        } else {
            // PTE无效
            if (!alloc) {
                return NULL;
            }
            // 分配新的页表页
            pgtbl_t new_table = (pgtbl_t)pmem_alloc(false);
            if (new_table == NULL) {
                return NULL;
            }
            memset(new_table, 0, PGSIZE);
            // 设置PTE指向新页表，准备下一轮循环
            *pte = PA_TO_PTE((uint64)new_table) | PTE_V;
            pgtbl = new_table;
        }
    }

    // 返回叶子级PTE
    uint64 leaf_index = VA_TO_VPN(va, 0);
    return &pgtbl[leaf_index];
}

/*
 * vm_mappages - 建立虚拟地址到物理地址的映射
 * 
 * @pgtbl: 页表
 * @va: 虚拟起始地址
 * @pa: 物理起始地址
 * @len: 映射长度
 * @perm: 权限位
 */
void vm_mappages(pgtbl_t pgtbl, uint64 va, uint64 pa, uint64 len, int perm)
{
    uint64 current_va, end_va;
    pte_t *pte;

    if (len == 0) {
        panic("vm_mappages: size cannot be zero");
    }

    // 对齐到页边界
    current_va = PG_ROUND_DOWN(va);
    end_va = PG_ROUND_DOWN(va + len - 1);

    for (;;) {
        //建立映射过程，中间没有页表，那么帮我新建一个
        pte = vm_getpte(pgtbl, current_va, true);
        if (pte == NULL) {
            panic("vm_mappages: failed to get PTE");
        }

        if (*pte & PTE_V) {
            // 页面已映射 - 更新权限
            *pte = PA_TO_PTE(pa) | perm | PTE_V;
        } else {
            // 新映射
            *pte = PA_TO_PTE(pa) | perm | PTE_V;
        }
        //不管之前有无映射，加上权限 perm,再加上有效位 PTE_V

        if (current_va == end_va) {
            break;
        }
        //处理下一页
        current_va += PGSIZE;
        pa += PGSIZE;
    }
}

/*
 * vm_unmappages - 解除虚拟地址映射
 * 
 * @pgtbl: 页表
 * @va: 虚拟起始地址
 * @len: 解除长度
 * @freeit: 是否释放物理页
 */
void vm_unmappages(pgtbl_t pgtbl, uint64 va, uint64 len, bool freeit)
{
    uint64 current_va;
    pte_t *pte;

    if ((va % PGSIZE) != 0) {
        panic("vm_unmappages: address not page aligned");
    }

    uint64 npages = (PG_ROUND_UP(len)) / PGSIZE;
    if (npages == 0) npages = 1;

    for (current_va = va; current_va < va + npages * PGSIZE; current_va += PGSIZE) {
        //找到页表项，注意这里传false，因为只是删除，不需要分配新页表
        pte = vm_getpte(pgtbl, current_va, false);
        if (pte == NULL) {
            panic("vm_unmappages: walk failed");
        }
        if (!(*pte & PTE_V)) {
            panic("vm_unmappages: page not mapped");
        }
        if (PTE_FLAGS(*pte) == PTE_V) {
            panic("vm_unmappages: not a leaf page");
        }

        // 如果要求释放物理内存，就把对应的物理页还给内存分配器
        if (freeit) {
            uint64 pa = PTE_TO_PA(*pte);
            pmem_free(pa, false);
        }
        *pte = 0;
        // 把PTE清0，代表映射断了
    }
}

/*
 * vm_print_recursive - 递归打印页表
 */
static void vm_print_recursive(pgtbl_t pgtbl, int level)
{
    for (int i = 0; i < 512; i++) {
        pte_t pte = pgtbl[i];
        if (pte & PTE_V) {
            // 打印缩进
            for (int j = 0; j < (2 - level); j++) {
                printf(" ");
            }
            printf("..%d: pte 0x%p pa 0x%p", i, pte, PTE_TO_PA(pte));

            // 打印权限
            if (pte & PTE_R) printf(" R");
            if (pte & PTE_W) printf(" W");
            if (pte & PTE_X) printf(" X");
            if (pte & PTE_U) printf(" U");
            printf("\n");

            // 如果不是叶子节点，递归打印下一级
            if (PTE_CHECK(pte) && level > 0) {
                vm_print_recursive((pgtbl_t)PTE_TO_PA(pte), level - 1);
            }
        }
    }
}

/*
 * vm_print - 打印页表内容（调试用）
 */
void vm_print(pgtbl_t pgtbl)
{
    printf("page table 0x%p\n", pgtbl);
    vm_print_recursive(pgtbl, 2);
}

//老师给出版本
void vm_print_2(pgtbl_t pgtbl)
{
    // 顶级页表，次级页表，低级页表
    pgtbl_t pgtbl_2 = pgtbl, pgtbl_1 = NULL, pgtbl_0 = NULL;
    pte_t pte;

    printf("level-2 pgtbl: pa = %p\n", pgtbl_2);
    for(int i = 0; i < PGSIZE / sizeof(pte_t); i++) 
    {
        pte = pgtbl_2[i];
        if(!((pte) & PTE_V)) continue;
        assert(PTE_CHECK(pte), "vm_print: pte check fail (1)");
        pgtbl_1 = (pgtbl_t)PTE_TO_PA(pte);
        printf(".. level-1 pgtbl %d: pa = %p\n", i, pgtbl_1);

        for(int j = 0; j < PGSIZE / sizeof(pte_t); j++)
        {
            pte = pgtbl_1[j];
            if(!((pte) & PTE_V)) continue;
            assert(PTE_CHECK(pte), "vm_print: pte check fail (2)");
            pgtbl_0 = (pgtbl_t)PTE_TO_PA(pte);
            printf(".. .. level-0 pgtbl %d: pa = %p\n", j, pgtbl_2);

            for(int k = 0; k < PGSIZE / sizeof(pte_t); k++) 
            {
                pte = pgtbl_0[k];
                if(!((pte) & PTE_V)) continue;
                assert(!PTE_CHECK(pte), "vm_print: pte check fail (3)");
                printf(".. .. .. physical page %d: pa = %p flags = %d\n", k, (uint64)PTE_TO_PA(pte), (int)PTE_FLAGS(pte));                
            }
        }
    }
}
/*
 * kvm_map - 向内核页表添加映射
 */
static void kvm_map(pgtbl_t kpgtbl, uint64 va, uint64 pa, uint64 sz, int perm)
{
    vm_mappages(kpgtbl, va, pa, sz, perm);
}

/*
 * kvm_make - 创建内核页表
 */
static pgtbl_t kvm_make(void)
{
    pgtbl_t kpgtbl;

    // 分配顶级页表
    kpgtbl = (pgtbl_t)pmem_alloc(false);
    if (kpgtbl == NULL) {
        panic("kvm_make: failed to allocate kernel page table");
    }
    memset(kpgtbl, 0, PGSIZE);

    // 映射 UART 寄存器，物理地址和虚拟地址都是 UART_BASE，内核往 UART_BASE写数据，CPU就会操作串口硬件
    kvm_map(kpgtbl, UART_BASE, UART_BASE, PGSIZE, PTE_R | PTE_W);

    // 映射 PLIC 中断控制器（4MB区域）
    kvm_map(kpgtbl, PLIC_BASE, PLIC_BASE, 0x400000, PTE_R | PTE_W);

    // 映射 CLINT 定时器控制器
    kvm_map(kpgtbl, CLINT_BASE, CLINT_BASE, 0x10000, PTE_R | PTE_W);

    // 映射 VIRTIO 磁盘设备
    kvm_map(kpgtbl, VIRTIO_BASE, VIRTIO_BASE, PGSIZE, PTE_R | PTE_W);

    // 映射 VIRT_TEST 设备（用于关机）
    // QEMU virt machine的test设备地址是0x100000
    #define VIRT_TEST_BASE 0x100000ul
    kvm_map(kpgtbl, VIRT_TEST_BASE, VIRT_TEST_BASE, PGSIZE, PTE_R | PTE_W);

