/*
 * proc.c - 进程生命周期与调度
 *
 * 主要内容：
 *   - proc_alloc/proc_free：进程结构分配/回收（注意返回时是否持有 p->lk）
 *   - proc_fork/proc_exit/proc_wait4：父子关系与退出回收
 *   - proc_scheduler/proc_sched/swtch：调度与上下文切换
 *   - proc_sleep/proc_wakeup：以 sleep_space 作为 channel 的睡眠/唤醒
 *
 * 并发与锁：
 *   - 每个 proc_t 有自己的自旋锁 p->lk，保护其状态字段。
 *   - wait_lock 保护 parent/child 关系与 ZOMBIE 回收关键路径。
 *   - 约定的锁顺序：先 wait_lock，再 p->lk（见 proc_exit/proc_wait4）。
 */

/*----------------外部空间------------------*/

// in trampoline.S
extern char trampoline[];

// in swtch.S
extern void swtch(context_t* old, context_t* new);

// in trap_user.c
extern void trap_user_return();

// in trap_user.c
extern void trap_user_handler();

// 内核页表
extern pgtbl_t kernel_pagetable;

/*----------------本地变量------------------*/

// 进程数组
static proc_t procs[NPROC];

// 第一个进程的指针
proc_t* proczero;

// 全局 pid 计数器与保护它的锁。
static int global_pid = 1;
static spinlock_t lk_pid;

// wait_lock：保护 parent-child 关系与 ZOMBIE 回收流程，避免并发竞争。
static spinlock_t wait_lock;

// 申请一个 pid（lk_pid 保护）。
static int alloc_pid()
{
    int tmp = 0;
    spinlock_acquire(&lk_pid);
    assert(global_pid >= 0, "alloc_pid: overflow");
    tmp = global_pid++;
    spinlock_release(&lk_pid);
    return tmp;
}

// 释放锁 + 调用 trap_user_return：新进程第一次被调度时从这里“落地”到用户态。
static void fork_return()
{
    // 由于调度器中上了锁，所以这里需要解锁
    proc_t* p = myproc();
    spinlock_release(&p->lk);
    trap_user_return();
}

/*
 * proc_alloc - 分配一个进程槽位并完成最小初始化。
 *
 * 工作：
 *   - 找到 UNUSED 槽位并持有 p->lk
 *   - 分配 pid、trapframe、用户页表（含 TRAMPOLINE/TRAPFRAME 映射）
 *   - 初始化内核上下文，使其第一次被调度时从 fork_return() 开始执行
 *
 * 返回约定：返回时仍然持有 p->lk（调用者负责在合适时机释放）。
 */
proc_t* proc_alloc()
{
    proc_t* p;

    // 遍历进程数组找到未使用的槽位
    for (int i = 0; i < NPROC; i++) {
        p = &procs[i];
        spinlock_acquire(&p->lk);
        if (p->state == UNUSED) {
            goto found;
        }
        spinlock_release(&p->lk);
    }
    return NULL;

found:
    // 分配PID
    p->pid = alloc_pid();

    // 分配trapframe物理页
    p->tf = (trapframe_t*)pmem_alloc(false);
    if (p->tf == NULL) {
        spinlock_release(&p->lk);
        return NULL;
    }
    memset(p->tf, 0, sizeof(trapframe_t));

    // 初始化页表（包含trapframe和trampoline的映射）
    p->pgtbl = proc_pgtbl_init((uint64)p->tf);
    if (p->pgtbl == NULL) {
        pmem_free((uint64)p->tf, false);
        p->tf = NULL;
        spinlock_release(&p->lk);
        return NULL;
    }

    // 设置上下文：ra 指向 fork_return，sp 指向内核栈顶。
    memset(&p->ctx, 0, sizeof(context_t));
    p->ctx.ra = (uint64)fork_return;
    p->ctx.sp = p->kstack + 2*PGSIZE;

    // 初始化其他字段
    p->parent = NULL;
    p->exit_state = 0;
    p->sleep_space = NULL;
    p->heap_top = 0;
    p->ustack_pages = 0;
    p->mmap = NULL;

    return p;
}

/*
 * proc_free - 回收进程资源并将其标记为 UNUSED。
 *
 * 约束：调用者需持有 p->lk。
 * 回收内容：文件描述符、trapframe、用户页表与 mmap 链表等。
 */
void proc_free(proc_t* p)
{
    // 释放文件描述符表
    for (int i = 0; i < FILE_PER_PROC; i++) {
        if (p->filelist[i] != NULL) {
            file_close(p->filelist[i]);
            p->filelist[i] = NULL;
        }
    }

    // 释放trapframe
    if (p->tf) {
        pmem_free((uint64)p->tf, false);
        p->tf = NULL;
    }

    // 释放页表及其管理的物理页
    if (p->pgtbl) {
        uvm_destroy_pgtbl(p->pgtbl);
        p->pgtbl = NULL;
    }

    // 释放mmap区域链表
    mmap_region_t* mmap = p->mmap;
    while (mmap != NULL) {
        mmap_region_t* next = mmap->next;
        mmap_region_free(mmap);
        mmap = next;
    }
    p->mmap = NULL;

    // 重置其他字段
    p->pid = 0;
    p->state = UNUSED;
    p->parent = NULL;
    p->exit_state = 0;
    p->sleep_space = NULL;
    p->heap_top = 0;
    p->ustack_pages = 0;
}

// 进程模块初始化：初始化 pid 锁、wait_lock，并为 procs[] 设置锁与内核栈地址。
void proc_init()
{
    // 初始化PID锁
    spinlock_init(&lk_pid, "pid");

    // 遍历进程数组，初始化每个进程的锁和内核栈地址
    for (int i = 0; i < NPROC; i++) {
        spinlock_init(&procs[i].lk, "proc");
        procs[i].kstack = KSTACK(i);//分配内核栈地址
        procs[i].state = UNUSED;//标记为空闲
    }

    spinlock_init(&wait_lock, "wait_lock");
}

// 获得一个初始化过的用户页表：完成 TRAMPOLINE 与 TRAPFRAME 映射。
pgtbl_t proc_pgtbl_init(uint64 trapframe)
{
    pgtbl_t pgtbl;

    // 分配顶级页表
    pgtbl = (pgtbl_t)pmem_alloc(false);
    if (pgtbl == NULL) {
        panic("proc_pgtbl_init: failed to allocate page table");
    }
    memset(pgtbl, 0, PGSIZE);

    // 映射跳板页（和内核页表共享同一虚拟地址和物理页）
    vm_mappages(pgtbl, TRAMPOLINE, (uint64)trampoline, PGSIZE, PTE_R | PTE_X);

    // 映射trapframe页
    vm_mappages(pgtbl, TRAPFRAME, trapframe, PGSIZE, PTE_R | PTE_W);

    return pgtbl;
}

/*
 * 第一个用户态进程的创建
 *
 * 其代码和数据位于 initcode.h 的 initcode 数组。
 * 用户地址空间布局（高地址向下）：
 *   TRAMPOLINE (1 page)
 *   TRAPFRAME  (1 page)
 *   USTACK     (1 page)
 *   ...
 *               <-- heap_top
 *   code+data  (1 page) 映射在虚拟地址 PGSIZE
 *   低地址空白 (1 page) 最低 4096 字节不映射，用于捕获 NULL/越界访问
 */
void proc_make_first()
{
    uint64 page;



    // 使用 proc_alloc 分配进程结构
    proczero = proc_alloc();
    if (proczero == NULL) {
        panic("proc_make_first: failed to allocate process");
    }

    // 第一个进程的pid设为0
    proczero->pid = 0;

    // ustack 映射 + 设置 ustack_pages 
    page = (uint64)pmem_alloc(false);
    if (page == 0) {
        panic("proc_make_first: failed to allocate user stack");
    }
    memset((void*)page, 0, PGSIZE);
    proczero->ustack_pages = 1;
    // 用户栈在 TRAPFRAME 下方
    uint64 ustack_va = TRAPFRAME - PGSIZE;
    vm_mappages(proczero->pgtbl, ustack_va, page, PGSIZE, PTE_R | PTE_W | PTE_U);

    // data + code 映射
    assert(initcode_len <= PGSIZE, "proc_make_first: initcode too big\n");
    page = (uint64)pmem_alloc(false);
    if (page == 0) {
        panic("proc_make_first: failed to allocate code page");
    }
    memset((void*)page, 0, PGSIZE);
    // 复制initcode到物理页
    memmove((void*)page, initcode, initcode_len);
    // 代码段在虚拟地址 PGSIZE (跳过最低的空白页)
    vm_mappages(proczero->pgtbl, PGSIZE, page, PGSIZE, PTE_R | PTE_W | PTE_X | PTE_U);

    // 设置 heap_top
    proczero->heap_top = 2 * PGSIZE;  // 代码段之后

    // 初始化 mmap 链表为空
    proczero->mmap = NULL;

    // tf字段设置
    proczero->tf->epc = PGSIZE;                     // 用户入口点（代码起始地址）
    proczero->tf->sp = ustack_va + PGSIZE;          // 用户栈顶（栈向下生长）
    proczero->tf->kernel_satp = r_satp();           // 内核页表
    proczero->tf->kernel_sp = proczero->kstack + PGSIZE;   // 内核栈顶
    proczero->tf->kernel_trap = (uint64)trap_user_handler;
    proczero->tf->kernel_hartid = r_tp();

    // 设置进程状态为 RUNNABLE，让调度器调度它。
    proczero->state = RUNNABLE;

    // 释放alloc时获取的锁
    spinlock_release(&proczero->lk);

    printf("[proc] proczero created (pid=%d), entry=0x%p, sp=0x%p\n", 
           proczero->pid, proczero->tf->epc, proczero->tf->sp);
}


