/*
 * trap_kernel.c - 内核态 trap 处理
 *
 * 路径：
 *   S-mode trap -> stvec 指向 kernel_vector（见 trap.S）
 *            -> kernel_vector 保存寄存器后调用 trap_kernel_handler()
 *
 * 这里负责：
 *   - 分发外设/时钟等中断
 *   - 对内核态异常给出诊断并尽量安全处理（本实现会尝试终止当前进程）
 */

// 中断信息
char* interrupt_info[16] = {
    "U-mode software interrupt",      // 0
    "S-mode software interrupt",      // 1
    "reserved-1",                     // 2
    "M-mode software interrupt",      // 3
    "U-mode timer interrupt",         // 4
    "S-mode timer interrupt",         // 5
    "reserved-2",                     // 6
    "M-mode timer interrupt",         // 7
    "U-mode external interrupt",      // 8
    "S-mode external interrupt",      // 9
    "reserved-3",                     // 10
    "M-mode external interrupt",      // 11
    "reserved-4",                     // 12
    "reserved-5",                     // 13
    "reserved-6",                     // 14
    "reserved-7",                     // 15
};

// 异常信息
char* exception_info[16] = {
    "Instruction address misaligned", // 0
    "Instruction access fault",       // 1
    "Illegal instruction",            // 2
    "Breakpoint",                     // 3
    "Load address misaligned",        // 4
    "Load access fault",              // 5
    "Store/AMO address misaligned",   // 6
    "Store/AMO access fault",         // 7
    "Environment call from U-mode",   // 8
    "Environment call from S-mode",   // 9
    "reserved-1",                     // 10
    "Environment call from M-mode",   // 11
    "Instruction page fault",         // 12
    "Load page fault",                // 13
    "reserved-2",                     // 14
    "Store/AMO page fault",           // 15
};

// in trap.S：内核态 trap 汇编入口（保存/恢复寄存器）。
extern void kernel_vector();

// 初始化 trap 中全局共享的东西（一次性）。
void trap_kernel_init()
{
    // 初始化系统时钟
    timer_create();
}

// 每 hart 初始化：配置 stvec 指向 kernel_vector。
void trap_kernel_inithart()
{
    // 设置stvec寄存器指向kernel_vector
    // 所有S-mode的陷阱都会跳转到kernel_vector
    w_stvec((uint64)kernel_vector);
}

// 外设中断处理（基于 PLIC）。
void external_interrupt_handler()
{
    // 从PLIC获取中断请求号
    int irq = plic_claim();

    if (irq == UART_IRQ) {
        // UART中断处理
        uart_intr();
    } else if (irq == VIRTIO_IRQ) {
        // VIRTIO磁盘中断处理
        virtio_disk_intr();
    } else if (irq != 0) {
        // 未知的外部中断
        printf("unexpected external interrupt irq=%d\n", irq);
    }
    // irq为0时直接忽略

    // 告知PLIC中断处理完成
    if (irq) {
        plic_complete(irq);
    }
}

// 时钟中断处理（基于 CLINT/M-mode timer -> S-mode software interrupt 的常见做法）。
void timer_interrupt_handler()
{
    // 直接调用 timer_update（timer_update 内部有锁保护）
    timer_update();

    // 清除软件中断标志
    w_sip(r_sip() & ~2);
}

// 在 kernel_vector() 里面调用：内核态 trap 处理的核心逻辑。
void trap_kernel_handler()
{
    uint64 sepc = r_sepc();          // 记录了发生异常时的pc值
    uint64 sstatus = r_sstatus();    // 与特权模式和中断相关的状态信息
    uint64 scause = r_scause();      // 引发trap的原因
    uint64 stval = r_stval();        // 发生trap时保存的附加信息(不同trap不一样)

    // 确认 trap 来自 S-mode 且当前中断已关闭（避免在 handler 内发生嵌套）。
    assert(sstatus & SSTATUS_SPP, "trap_kernel_handler: not from s-mode");
    assert(intr_get() == 0, "trap_kernel_handler: interreput enabled");

    // scause 最高位表示是 interrupt(1) 还是 exception(0)。
    // 低位为 cause code；这里用 &0xf 足以覆盖本实现关心的常见 code（1/5/9/8 等）。
    int trap_id = scause & 0xf;
    int is_interrupt = (scause >> 63) & 1;

    // 中断异常处理核心逻辑
    if (is_interrupt) {
        // 中断处理
        switch (trap_id) {
            case 1: // S-mode software interrupt (由M-mode定时器中断触发)
                timer_interrupt_handler();
                // 如果有运行中的进程，触发调度。
                if (myproc() != NULL && myproc()->state == RUNNING) {
                    proc_yield();
                }
                break;
            case 5: // S-mode timer interrupt
                timer_interrupt_handler();
                // 如果有运行中的进程，触发调度。
                if (myproc() != NULL && myproc()->state == RUNNING) {
                    proc_yield();
                }
                break;
            case 9: // S-mode external interrupt
                external_interrupt_handler();
                break;
            default:
                printf("unknown interrupt: %s (trap_id=%d)\n", 
                       interrupt_info[trap_id], trap_id);
                printf("scause=%p sepc=%p stval=%p\n", scause, sepc, stval);
                panic("trap_kernel_handler: unexpected interrupt");
                break;
        }
    } else {
        // 异常处理
        printf("kernel exception: %s (trap_id=%d)\n", 
               exception_info[trap_id], trap_id);
        printf("scause=%p sepc=%p stval=%p\n", scause, sepc, stval);

        // 如果有运行中的进程，安全终止它（避免内核直接 panic 影响后续测试）。
        proc_t* p = myproc();
        if (p != NULL && p->state != ZOMBIE) {
            printf("[EXCEPTION] Terminating process %d\n", p->pid);
            // 直接设置进程状态为 ZOMBIE，避免复杂的 proc_exit 可能导致递归
            p->exit_state = 0xff00;  // 表示异常退出
            p->state = ZOMBIE;
            // 切换到调度器
            spinlock_acquire(&p->lk);
            proc_sched();
            // 不会到达这里
        } else if (p != NULL && p->state == ZOMBIE) {
            // 进程已经是 ZOMBIE，忽略并切换
            spinlock_acquire(&p->lk);
            proc_sched();
        } else {
            panic("trap_kernel_handler: unexpected exception (no process)");
        }
    }

    // 恢复sepc和sstatus（可能在处理过程中被修改）
    w_sepc(sepc);
    w_sstatus(sstatus);
}

