/*
 * syscall.c - 系统调用分发与参数读取
 *
 * 入口来自用户态 trap（见 trap_user.c）：
 *   - trap_user_handler 识别 scause=ecall 后调用 syscall()
 *
 * 约定（Linux/RISC-V 风格）：
 *   - a7 为系统调用号
 *   - a0-a5 为参数
 *   - 返回值写回 a0
 */

// 系统调用分发：读取 a7 号并调用对应 sys_* 实现，最后把返回值写回 a0。
void syscall()
{
    proc_t* p = myproc();

    // 从 a7 寄存器获取系统调用号
    int num = p->tf->a7;
    uint64 ret = -1;


    switch(num) {
        // 文件系统相关
        case SYS_getcwd:     ret = sys_getcwd(); break;
        case SYS_dup:        ret = sys_dup(); break;
        case SYS_dup3:       ret = sys_dup3(); break;
        case SYS_chdir:      ret = sys_chdir(); break;
        case SYS_openat:     ret = sys_openat(); break;
        case SYS_close:      ret = sys_close(); break;
        case SYS_pipe2:      ret = sys_pipe2(); break;
        case SYS_getdents64: ret = sys_getdents64(); break;
        case SYS_read:       ret = sys_read(); break;
        case SYS_write:      ret = sys_write(); break;
        case SYS_fstat:      ret = sys_fstat(); break;
        case SYS_mkdirat:    ret = sys_mkdirat(); break;
        case SYS_unlinkat:   ret = sys_unlinkat(); break;
        case SYS_mount:      ret = sys_mount(); break;
        case SYS_umount2:    ret = sys_umount2(); break;

        // 进程管理相关
        case SYS_exit:       sys_exit(); ret = 0; break;
        case SYS_exit_group: sys_exit(); ret = 0; break;
        case SYS_clone:      ret = sys_clone(); break;
        case SYS_execve:     ret = sys_execve(); break;
        case SYS_wait4:      ret = sys_wait4(); break;
        case SYS_getpid:     ret = sys_getpid(); break;
        case SYS_getppid:    ret = sys_getppid(); break;
        case SYS_getuid:     ret = sys_getuid(); break;
        case SYS_geteuid:    ret = sys_geteuid(); break;
        case SYS_getgid:     ret = sys_getgid(); break;
        case SYS_getegid:    ret = sys_getegid(); break;

        // 内存管理相关
        case SYS_brk:        ret = sys_brk(); break;
        case SYS_mmap:       ret = sys_mmap(); break;
        case SYS_munmap:     ret = sys_munmap(); break;

        // 其他
        case SYS_times:      ret = sys_times(); break;
        case SYS_uname:      ret = sys_uname(); break;
        case SYS_sched_yield: ret = sys_yield(); break;
        case SYS_gettimeofday: ret = sys_gettimeofday(); break;
        case SYS_nanosleep:  ret = sys_nanosleep(); break;
        case SYS_set_tid_address: ret = sys_set_tid_address(); break;

        default:
            // 未实现/未知 syscall：按约定返回 -1，并打印诊断方便对齐测试点。
            printf("[syscall] unknown: %d from pid %d\n", num, p->pid);
            ret = -1;
            break;
    }

    p->tf->a0 = ret;
}

/*
 * 参数读取：
 *   - 纯数值参数：直接从 trapframe 的 a0-a5 读取。
 *   - 用户指针参数：不能直接解引用，必须通过 uvm_copyin/uvm_copyin_str
 *     或 uvm_copyout 在“用户页表 pgtbl”语境下安全访问。
 *
 * 经验法则：
 *   - arg_raw/arg_uint32/arg_uint64/arg_int64 只负责“取寄存器里的值”，
 *     并不保证该值所指向的内存有效。
 *   - 一旦该值要作为用户指针使用，就必须显式 copyin/copyout。
 */

// 读取第 n 个参数（来自 a0-a5）。注意：这里返回的只是寄存器值。
uint64 arg_raw(int n)
{   
    proc_t* proc = myproc();
    switch(n) {
        case 0:
            return proc->tf->a0;
        case 1:
            return proc->tf->a1;
        case 2:
            return proc->tf->a2;
        case 3:
            return proc->tf->a3;
        case 4:
            return proc->tf->a4;
        case 5:        
            return proc->tf->a5;
        default:
            panic("arg_raw: illegal arg num");
            return -1;
    }
}

// 读取 n 号参数, 作为 uint32 存储
void arg_uint32(int n, uint32* ip)
{
    *ip = arg_raw(n);
}

// 读取 n 号参数, 作为 uint64 存储
void arg_uint64(int n, uint64* ip)
{
    *ip = arg_raw(n);
}

// 读取 n 号参数, 作为 int64 存储
void arg_int64(int n, int64* ip)
{
    *ip = (int64)arg_raw(n);
}

/*
 * 读取第 n 个参数指向的用户字符串到 buf。
 *
 * @param n      参数编号（0-5）
 * @param buf    内核缓冲区
 * @param maxlen 最多拷贝字节数（包含 '\0'；具体由 uvm_copyin_str 语义决定）
 */
void arg_str(int n, char* buf, int maxlen)
{
    proc_t* p = myproc();
    uint64 addr;
    arg_uint64(n, &addr);

    uvm_copyin_str(p->pgtbl, (uint64)buf, addr, maxlen);
}

