    // syscall(SYS_clone, flags, stack, ptid, tls, ctid)
    // 其中 stack 指向用户栈（已预留 16 字节存放 func/arg）
    uint64 flags = 0;
    uint64 stack = 0;
    uint64 ptid = 0;
    uint64 tls = 0;
    uint64 ctid = 0;

    arg_uint64(0, &flags);
    arg_uint64(1, &stack);
    arg_uint64(2, &ptid);
    arg_uint64(3, &tls);
    arg_uint64(4, &ctid);

    (void)flags;
    (void)ptid;
    (void)tls;
    (void)ctid;

