/*
 * sys_execve - 执行程序。
 *
 * 核心流程：
 *   1) 从用户态拷贝 filename/argv 到内核缓冲区（因为后续会替换页表）
 *   2) 通过 EXT4 读取 ELF 到对齐的静态缓冲区
 *   3) 销毁旧地址空间，创建新用户页表，并清空旧 mmap 记录
 *   4) elf_load() 把 PT_LOAD 段映射进新页表，得到 entry 与 heap_top
 *   5) 分配用户栈，压入 argv 字符串与 argv 指针数组
 *   6) 设置 trapframe（epc/sp/a0/a1），返回到用户态从 entry 开始执行
 *
 * 兼容性：envp 暂不处理。
 */
uint64 sys_execve(void)
{
    uint64 filename_addr, argv_addr, envp_addr;

    arg_uint64(0, &filename_addr);
    arg_uint64(1, &argv_addr);
    arg_uint64(2, &envp_addr);

    proc_t* p = myproc();
    char filename[256];

    // 从用户态页表拷贝文件名（以 '\0' 结尾）。
    uvm_copyin_str(p->pgtbl, (uint64)filename, filename_addr, sizeof(filename));

    // 先把 argv 复制到内核（因为接下来会替换页表，用户地址将不可再用）。
    #define EXEC_MAX_ARGC 16
    #define EXEC_MAX_ARG_LEN 128
    char kargv[EXEC_MAX_ARGC][EXEC_MAX_ARG_LEN];
    int argc = 0;

    if (argv_addr != 0) {
        for (argc = 0; argc < EXEC_MAX_ARGC; argc++) {
            uint64 argp = 0;
            uvm_copyin(p->pgtbl, (uint64)&argp, argv_addr + (uint64)argc * sizeof(uint64), sizeof(uint64));
            if (argp == 0) {
                break;
            }
            uvm_copyin_str(p->pgtbl, (uint64)kargv[argc], argp, EXEC_MAX_ARG_LEN);
        }
    }

    extern int ext4_read_file(const char* filename, void* buf, uint32 max_size);
    extern int ext4_get_file_size(const char* filename);

    // 使用静态缓冲区读取 ELF（避免运行时分配连续大块内存，且保证对齐）。
    #define EXEC_ELF_BUF_SIZE (128 * 1024)
    static uint8 exec_elf_buf[EXEC_ELF_BUF_SIZE] __attribute__((aligned(4096)));

    uint32 file_size = ext4_get_file_size(filename);
    if (file_size == 0 || file_size > EXEC_ELF_BUF_SIZE) {
        return -1;
    }

    int n = ext4_read_file(filename, exec_elf_buf, file_size);
    if (n < (int)sizeof(elf64_ehdr_t)) {
        return -1;
    }

    // 丢弃旧地址空间，创建新页表（保留同一个 trapframe 物理页）。
    if (p->pgtbl) {
        uvm_destroy_pgtbl(p->pgtbl);
    }
    p->pgtbl = proc_pgtbl_init((uint64)p->tf);
    if (p->pgtbl == NULL) {
        return -1;
    }

    // 丢弃旧的 mmap 记录（避免新地址空间与旧记录不一致）。
    mmap_region_t* mmap = p->mmap;
    while (mmap != NULL) {
        mmap_region_t* next = mmap->next;
        mmap_region_free(mmap);
        mmap = next;
    }
    p->mmap = NULL;

    // 加载 ELF 到新页表。
    uint64 entry = 0, heap_top = 0;
    if (elf_load(exec_elf_buf, (uint32)n, p->pgtbl, &entry, &heap_top) != 0) {
        return -1;
    }
    p->heap_top = heap_top;

    // 分配用户栈（固定 4 页；栈顶放在 TRAPFRAME 下方）。
    for (uint32 i = 0; i < 4; i++) {
        uint64 ustack_page = (uint64)pmem_alloc(false);
        if (ustack_page == 0) {
            return -1;
        }
        memset((void*)ustack_page, 0, PGSIZE);
        uint64 ustack_va = TRAPFRAME - (i + 1) * PGSIZE;
        vm_mappages(p->pgtbl, ustack_va, ustack_page, PGSIZE, PTE_R | PTE_W | PTE_U);
    }
    p->ustack_pages = 4;

    // 构造用户栈：写入 argv 字符串与 argv 指针数组。
    uint64 sp = TRAPFRAME;
    uint64 uargv[EXEC_MAX_ARGC + 1];

    for (int i = argc - 1; i >= 0; i--) {
        uint32 len = (uint32)strlen(kargv[i]) + 1;
        sp -= len;
        sp &= ~0xFul; // 16字节对齐
        uvm_copyout(p->pgtbl, sp, (uint64)kargv[i], len);
        uargv[i] = sp;
    }
    uargv[argc] = 0;

    sp -= (uint64)(argc + 1) * sizeof(uint64);
    sp &= ~0xFul;
    uint64 argv_user = sp;
    uvm_copyout(p->pgtbl, argv_user, (uint64)uargv, (uint32)((argc + 1) * sizeof(uint64)));

    // 设置 trapframe：用户态入口、栈指针，以及 main(argc, argv) 约定。
    p->tf->epc = entry;
    p->tf->sp = sp;
    p->tf->a0 = (uint64)argc;
    p->tf->a1 = argv_user;

    (void)envp_addr;
    return 0;
}

