static int read_sector(uint32 sector, void* dst)
{
    uint32 sectors_per_block = BLOCK_SIZE / SECTOR_SIZE;
    uint32 block_num = sector / sectors_per_block;
    uint32 offset = (sector % sectors_per_block) * SECTOR_SIZE;
    buf_t* b = buf_read(block_num);
    if (b == NULL) {
        return -1;
    }
    memmove(dst, b->data + offset, SECTOR_SIZE);
    buf_release(b);
    return 0;
}

static int read_sectors(uint32 start_sector, uint32 count, void* dst)
{
    uint8* p = (uint8*)dst;
    for (uint32 i = 0; i < count; i++) {
        if (read_sector(start_sector + i, p) < 0) {
            return -1;
        }
        p += SECTOR_SIZE;
    }
    return 0;
}

static uint64 extent_start(const ext4_extent_t* ex)
{
    return ((uint64)ex->start_hi << 32) | ex->start_lo;
}

static uint64 idx_leaf(const ext4_extent_idx_t* idx)
{
    return ((uint64)idx->leaf_hi << 32) | idx->leaf_lo;
}

static int read_block(uint64 block, void* dst)
{
    uint32 sectors = ext4_block_size / SECTOR_SIZE;
    return read_sectors((uint32)(block * sectors), sectors, dst);
}

static uint64 inode_size_bytes(const ext4_inode_t* inode)
{
    return ((uint64)inode->size_high << 32) | inode->size_lo;
}

static int read_inode(uint32 ino, ext4_inode_t* inode)
{
    uint32 group = (ino - 1) / ext4_inodes_per_group;
    uint32 index = (ino - 1) % ext4_inodes_per_group;
    uint32 desc_per_block = ext4_block_size / ext4_desc_size;
    uint32 desc_block = (ext4_block_size == 1024 ? 2 : 1) + group / desc_per_block;
    uint32 desc_offset = (group % desc_per_block) * ext4_desc_size;
    uint8* block = (uint8*)pmem_alloc(false);
    if (block == NULL) {
        return -1;
    }

    if (read_block(desc_block, block) < 0) {
        pmem_free((uint64)block, false);
        return -1;
    }

    ext4_group_desc_t* gd = (ext4_group_desc_t*)(block + desc_offset);
    uint64 inode_table = ((uint64)gd->inode_table_hi << 32) | gd->inode_table_lo;
    uint64 inode_pos = (uint64)index * ext4_inode_size;
    uint64 inode_block = inode_table + inode_pos / ext4_block_size;
    uint32 inode_offset = inode_pos % ext4_block_size;

    if (read_block(inode_block, block) < 0) {
        pmem_free((uint64)block, false);
        return -1;
    }

    memmove(inode, block + inode_offset, sizeof(ext4_inode_t));
    pmem_free((uint64)block, false);
    return 0;
}

static int copy_extent_blocks(const ext4_extent_t* ex, uint8* out, uint32 max_size,
                              uint32* bytes_read, uint64 file_size)
{
    uint32 len = ex->len & 0x7FFF;
    uint64 start = extent_start(ex);
    uint8* block = (uint8*)pmem_alloc(false);
    if (block == NULL) {
        return -1;
    }

    for (uint32 i = 0; i < len && *bytes_read < max_size && *bytes_read < file_size; i++) {
        if (read_block(start + i, block) < 0) {
            pmem_free((uint64)block, false);
            return -1;
        }
        uint32 copy = ext4_block_size;
        if (*bytes_read + copy > max_size) {
            copy = max_size - *bytes_read;
        }
        if ((uint64)*bytes_read + copy > file_size) {
            copy = (uint32)(file_size - *bytes_read);
        }
        memmove(out + *bytes_read, block, copy);
        *bytes_read += copy;
    }

    pmem_free((uint64)block, false);
    return 0;
}

static int read_extent_tree(uint8* node, uint8* out, uint32 max_size,
                            uint32* bytes_read, uint64 file_size)
{
    ext4_extent_header_t* eh = (ext4_extent_header_t*)node;
    if (eh->magic != EXT4_EXTENT_MAGIC) {
        return -1;
    }

    if (eh->depth == 0) {
        ext4_extent_t* ex = (ext4_extent_t*)(node + sizeof(ext4_extent_header_t));
        for (uint32 i = 0; i < eh->entries; i++) {
            if (copy_extent_blocks(&ex[i], out, max_size, bytes_read, file_size) < 0) {
                return -1;
            }
        }
        return 0;
    }

    if (eh->depth == 1) {
        uint8* child = (uint8*)pmem_alloc(false);
        if (child == NULL) {
            return -1;
        }
        ext4_extent_idx_t* idx = (ext4_extent_idx_t*)(node + sizeof(ext4_extent_header_t));
        for (uint32 i = 0; i < eh->entries; i++) {
            if (read_block(idx_leaf(&idx[i]), child) < 0 ||
                read_extent_tree(child, out, max_size, bytes_read, file_size) < 0) {
                pmem_free((uint64)child, false);
                return -1;
            }
        }
        pmem_free((uint64)child, false);
        return 0;
    }

    return -1;
}

static int read_inode_data(const ext4_inode_t* inode, void* dst, uint32 max_size)
{
    uint32 bytes_read = 0;
    uint64 file_size = inode_size_bytes(inode);
