// ===================== 评测用简易 RAM 文件系统 =====================

#define RAM_FILE_MAGIC 100
#define RAMFS_MAX_FILES 32
#define RAMFS_MAX_PATH  128
#define RAMFS_MAX_PAGES 16  // 每个文件最多 64KB

typedef struct ramfile {
    int used;
    int ref;
    int deleted;
    char path[RAMFS_MAX_PATH];
    uint32 size;
    uint64 pages[RAMFS_MAX_PAGES];
} ramfile_t;

static ramfile_t ramfs[RAMFS_MAX_FILES];
static spinlock_t lk_ramfs;

static ramfile_t* ramfs_lookup_locked(const char* path)
{
    for (int i = 0; i < RAMFS_MAX_FILES; i++) {
        if (ramfs[i].used && strncmp(ramfs[i].path, path, RAMFS_MAX_PATH) == 0) {
            return &ramfs[i];
        }
    }
    return NULL;
}

static void ramfs_free_pages(ramfile_t* rf)
{
    for (int i = 0; i < RAMFS_MAX_PAGES; i++) {
        if (rf->pages[i] != 0) {
            pmem_free(rf->pages[i], false);
            rf->pages[i] = 0;
        }
    }
    rf->size = 0;
}

static void ramfs_put(ramfile_t* rf)
{
    spinlock_acquire(&lk_ramfs);
    if (rf->ref <= 0) {
        spinlock_release(&lk_ramfs);
        return;
    }
    rf->ref--;
    if (rf->ref == 0 && rf->deleted) {
        ramfs_free_pages(rf);
        rf->used = 0;
        rf->deleted = 0;
        rf->path[0] = 0;
    }
    spinlock_release(&lk_ramfs);
}

static int ramfs_get_or_create(const char* path, bool create, ramfile_t** out)
{
    spinlock_acquire(&lk_ramfs);

    ramfile_t* rf = ramfs_lookup_locked(path);
    if (rf != NULL) {
        if (rf->deleted) {
            spinlock_release(&lk_ramfs);
            return -1;
        }
        rf->ref++;
        *out = rf;
        spinlock_release(&lk_ramfs);
        return 0;
    }

    if (!create) {
        spinlock_release(&lk_ramfs);
        return -1;
    }

    for (int i = 0; i < RAMFS_MAX_FILES; i++) {
        if (!ramfs[i].used) {
            ramfs[i].used = 1;
            ramfs[i].ref = 1;
            ramfs[i].deleted = 0;
            ramfs[i].size = 0;
            memset(ramfs[i].pages, 0, sizeof(ramfs[i].pages));
            memset(ramfs[i].path, 0, sizeof(ramfs[i].path));
            safestrcpy(ramfs[i].path, path, RAMFS_MAX_PATH);
            *out = &ramfs[i];
            spinlock_release(&lk_ramfs);
            return 0;
        }
    }

    spinlock_release(&lk_ramfs);
    return -1;
}

file_t* file_open_ram(char* path, uint32 open_mode)
{
    ramfile_t* rf = NULL;
    bool create = (open_mode & MODE_CREATE) ? true : false;
    if (ramfs_get_or_create(path, create, &rf) < 0) {
        return NULL;
    }

    file_t* file = file_alloc();
    file->type = FD_FILE;
    file->readable = (open_mode & MODE_READ) ? true : false;
    file->writable = (open_mode & MODE_WRITE) ? true : false;
    file->offset = 0;
    file->ip = NULL;
    file->major = RAM_FILE_MAGIC;
    file->pipe = (pipe_t*)rf; // 复用 pipe 指针存放 ramfile 句柄
    return file;
}

int file_unlink_ram(char* path)
{
    spinlock_acquire(&lk_ramfs);
    ramfile_t* rf = ramfs_lookup_locked(path);
    if (rf == NULL || rf->deleted) {
        spinlock_release(&lk_ramfs);
        return -1;
    }
    rf->deleted = 1;
    if (rf->ref == 0) {
        ramfs_free_pages(rf);
        rf->used = 0;
        rf->deleted = 0;
        rf->path[0] = 0;
    }
    spinlock_release(&lk_ramfs);
    return 0;
}

