// 供文件系统使用的控制台读写函数

#include "common.h"
#include "mem/vmem.h"
#include "proc/cpu.h"

// 控制台写入（用于 sys_write）：逐字节输出到 UART。
uint32 console_write(uint32 len, uint64 src, bool user_src)
{
  uint32 i;
  char c;

  for (i = 0; i < len; i++) {
    if (user_src) {
      // 从用户空间逐字节读取
      uvm_copyin(myproc()->pgtbl, (uint64)&c, src + i, 1);
    } else {
      c = ((char*)src)[i];
    }
    uart_putc_sync(c);
  }

  return i;
}

// 控制台读取（用于 sys_read）：同步轮询读取，直到读满/遇到换行/EOF。
uint32 console_read(uint32 len, uint64 dst, bool user_dst)
{
  uint32 i = 0;
  char c;

  for (i = 0; i < len; i++) {
    // 同步阻塞读取
    while ((c = uart_getc_sync()) == -1) {
      // 可以在这里加入yield让出CPU
    }

    if (user_dst) {
      uvm_copyout(myproc()->pgtbl, dst + i, (uint64)&c, 1);
    } else {
      ((char*)dst)[i] = c;
    }

    // 遇到换行或EOF结束
    if (c == '\n' || c == '\r' || c == 4) {
      i++;
      break;
    }
  }

  return i;
}

