/*
 * timer.c - 定时器中断与系统时钟 ticks
 *
 * 分两部分：
 *   - M-mode：配置 CLINT 定时器中断，并在 timer_vector 中触发 S-mode software interrupt
 *   - S-mode：维护 sys_timer.ticks，并唤醒 sleep 在该 channel 上的进程
 */

/*-------------------- 工作在M-mode --------------------*/

// in trap.S M-mode时钟中断处理流程()
extern void timer_vector();

// 每个 CPU 在 timer_vector 中需要的临时空间：
//   [0..2] 保存 a1/a2/a3，[3] 保存 MTIMECMP 地址，[4] 保存 INTERVAL。
static uint64 mscratch[NCPU][5];

// 时钟初始化（M-mode）：为当前 hart 配置 mtvec/mscratch/mtimecmp，并开启 MTIE。
void timer_init()
{
    // 每个CPU都有独立的定时器中断源
    int id = r_mhartid();

    // 向CLINT请求定时器中断
    // 设置 MTIMECMP = MTIME + INTERVAL
    *(uint64*)CLINT_MTIMECMP(id) = *(uint64*)CLINT_MTIME + INTERVAL;

    // 在mscratch[]中为timer_vector准备信息
    // mscratch[0..2]: timer_vector保存寄存器的空间
    // mscratch[3]: CLINT MTIMECMP寄存器地址
    // mscratch[4]: 定时器中断之间期望的间隔
    uint64 *scratch = &mscratch[id][0];
    scratch[3] = CLINT_MTIMECMP(id);
    scratch[4] = INTERVAL;
    w_mscratch((uint64)scratch);

    // 设置机器模式的陷阱处理程序,mtvec寄存器保存中断向量地址。当M-mode中断发生时，CPU自动跳转到这个地址执行
    w_mtvec((uint64)timer_vector);

    // 启用机器模式中断
    w_mstatus(r_mstatus() | MSTATUS_MIE);

    // 启用机器模式定时器中断
    w_mie(r_mie() | MIE_MTIE);

    // mstatus.MIE 和 mie.MTIE 分别是全局中断开关和定时器中断开关
}


/*--------------------- 工作在S-mode --------------------*/

// 系统时钟 (导出供sleep使用)
timer_t sys_timer;

// 时钟创建：初始化 sys_timer 与其锁（一次性）。
void timer_create()
{
    sys_timer.ticks = 0;
    spinlock_init(&sys_timer.lk, "timer");
}

// 时钟更新：ticks++ 并唤醒等待 ticks 的进程。
void timer_update()
{
    spinlock_acquire(&sys_timer.lk);
    sys_timer.ticks++;
    proc_wakeup(&sys_timer.ticks);
    spinlock_release(&sys_timer.lk);
}

// 返回系统时钟 ticks。
uint64 timer_get_ticks()
{
    return sys_timer.ticks;
}

/*
 * virtio.c - QEMU virtio-blk（虚拟磁盘）驱动
 *
 * QEMU 侧常见配置：-device virtio-blk-device,drive=x0,bus=virtio-mmio-bus.0
 *
 * 对外提供三个核心函数：
 *   - virtio_disk_init()：初始化 virtio 队列与设备状态
 *   - virtio_disk_rw(b, write)：以 buf_t 为单位提交读/写请求
 *   - virtio_disk_intr()：外部中断处理，完成请求并唤醒等待者
 *
 * 并发说明：
 *   - disk.vdisk_lock 保护 ring/descriptor 相关共享状态。
 *   - 本实现为了适配“早期无进程阶段”与简化逻辑，等待路径会退化为自旋等待。
 */

