// 内存管理相关 - 保留基础工具宏

#define PGSHIFT 12  // bits of offset within a page

// 地址对齐宏（向上/向下对齐到页边界）
// ~(PGSIZE-1) 的二进制是低12位均为0，直接把地址a的低12位抹零
// 先给sz加上一个 PGSIZE - 1，再抹零，确保只要超过了页边界一点点，高位就会进位到下一页
#define PG_ROUND_UP(sz)  (((sz)+PGSIZE-1) & ~(PGSIZE-1))
#define PG_ROUND_DOWN(a) (((a)) & ~(PGSIZE-1))

// 注意：PTE_*, PA2PTE, PTE2PA等定义已移至 mem/vmem.h

/* memory leyout */
#ifndef __MEMLAYOUT_H__
#define __MEMLAYOUT_H__

// 内核基地址 (使用OpenSBI时从0x80200000开始)
#define KERNEL_BASE 0x80200000ul

// UART 相关
#define UART_BASE  0x10000000ul
#define UART_IRQ   10

// platform-level interrupt controller(PLIC)
#define PLIC_BASE 0x0c000000ul
// PLIC寄存器区域的起始基地址，PILC是处理外部中断等的枢纽
#define PLIC_PRIORITY(id) (PLIC_BASE + (id) * 4)
#define PLIC_PENDING (PLIC_BASE + 0x1000)
#define PLIC_MENABLE(hart) (PLIC_BASE + 0x2000 + (hart)*0x100)
#define PLIC_SENABLE(hart) (PLIC_BASE + 0x2080 + (hart)*0x100)
#define PLIC_MPRIORITY(hart) (PLIC_BASE + 0x200000 + (hart)*0x2000)
#define PLIC_SPRIORITY(hart) (PLIC_BASE + 0x201000 + (hart)*0x2000)
#define PLIC_MCLAIM(hart) (PLIC_BASE + 0x200004 + (hart)*0x2000)
#define PLIC_SCLAIM(hart) (PLIC_BASE + 0x201004 + (hart)*0x2000)

// core local interruptor(CLINT)
// CLINT处理本地中断，主要是定时器中断
#define CLINT_BASE 0x2000000ul
#define CLINT_MSIP(hartid) (CLINT_BASE + 4 * (hartid))
#define CLINT_MTIMECMP(hartid) (CLINT_BASE + 0x4000 + 8 * (hartid))
#define CLINT_MTIME (CLINT_BASE + 0xBFF8)

// 物理内存结束地址 (128MB, 从0x80000000开始到0x88000000)
#define PHYSTOP (0x80000000ul + 128*1024*1024)

// 用户态虚拟地址空间布局
// 最大虚拟地址 (SV39: 2^38)
#define VA_MAX (1ul << 38)

// 跳板页：映射在虚拟地址空间最高处
// 内核和用户态共享同一虚拟地址
#define TRAMPOLINE (VA_MAX - PGSIZE)

// trapframe页：紧邻跳板页下方
#define TRAPFRAME (TRAMPOLINE - PGSIZE)

// 内核栈：每个CPU一个，从 TRAMPOLINE 往下分配
// 每个栈由一个guard页和一个栈页组成
#define KSTACK(cpu) (TRAMPOLINE - ((cpu) + 1) * 2 * PGSIZE)

//virtio相关
#define VIRTIO_BASE 0x10001000ul
#define VIRTIO_IRQ 1

#endif

/*
PLIC和CLINT是实现中断处理的两个关键硬件组件
CLINT产生时钟中断和软件中断，每个核心有独立的定时器
PLIC负责管理外部设备中断（如UART键盘输入），负责中断优先级仲裁
*/

#ifndef __PROC_H__
#define __PROC_H__

#include "common.h"
#include "mem/mmap.h"
#include "lib/lock.h"

/*
 * proc.h - 进程/调度核心数据结构
 *
 * 关键对象：
 *   - proc_t：一个“进程”的内核态管理结构，包含状态、页表、trapframe、内核栈与上下文。
 *   - context_t：内核态上下文切换时保存/恢复的寄存器集合（callee-saved + ra/sp）。
 *   - trapframe_t：用户态 <-> 内核态切换时保存的寄存器现场；布局需与 trampoline.S 匹配。
 *
 * 并发约束：
 *   - proc_t::lk 保护该进程的可变字段（见注释“需要持有锁才能修改”的字段）。
 *   - wait_lock 保护 parent/child 关系与 ZOMBIE 回收的关键路径（见 proc.c）。
 */

// 最大进程数
#define NPROC 64

// 页表类型定义
typedef uint64* pgtbl_t;

// mmap_region定义
typedef struct mmap_region mmap_region_t;

// context：内核态上下文切换时保存的寄存器集合。
// swtch(old, new) 会把当前 CPU 的寄存器保存到 old，并从 new 恢复。
typedef struct context {
    uint64 ra; // 返回地址：下次执行从哪里开始
    uint64 sp; // 栈指针：栈在哪里

    // callee-saved
    uint64 s0;
    uint64 s1;
    uint64 s2;
    uint64 s3;
    uint64 s4;
    uint64 s5;
    uint64 s6;
    uint64 s7;
    uint64 s8;
    uint64 s9;
    uint64 s10;
    uint64 s11;
} context_t;

// trapframe：用户态 trap 时保存的寄存器现场；偏移必须与 trampoline.S 的 sd/ld 顺序一致。
typedef struct trapframe {
    /*   0 */ uint64 kernel_satp;   // kernel page table
    /*   8 */ uint64 kernel_sp;     // top of process's kernel stack
    /*  16 */ uint64 kernel_trap;   // usertrap()
    /*  24 */ uint64 epc;           // saved user program counter
    /*  32 */ uint64 kernel_hartid; // saved kernel tp

    /*  40 */ uint64 ra;
    /*  48 */ uint64 sp;
    /*  56 */ uint64 gp;
    /*  64 */ uint64 tp;
    /*  72 */ uint64 t0;
    /*  80 */ uint64 t1;
    /*  88 */ uint64 t2;
    /*  96 */ uint64 s0;
    /* 104 */ uint64 s1;
    /* 112 */ uint64 a0;
    /* 120 */ uint64 a1;
    /* 128 */ uint64 a2;
    /* 136 */ uint64 a3;
    /* 144 */ uint64 a4;
    /* 152 */ uint64 a5;
    /* 160 */ uint64 a6;
    /* 168 */ uint64 a7;
    /* 176 */ uint64 s2;
    /* 184 */ uint64 s3;
    /* 192 */ uint64 s4;
    /* 200 */ uint64 s5;
    /* 208 */ uint64 s6;
    /* 216 */ uint64 s7;
    /* 224 */ uint64 s8;
    /* 232 */ uint64 s9;
    /* 240 */ uint64 s10;
    /* 248 */ uint64 s11;
    /* 256 */ uint64 t3;
    /* 264 */ uint64 t4;
    /* 272 */ uint64 t5;
    /* 280 */ uint64 t6;
} trapframe_t;

/*
 * 进程状态集合
 *
 * 常见状态变换：
 *   UNUSED   -> RUNNABLE   进程初始化完成
 *   RUNNABLE -> RUNNING    被调度上 CPU
 *   RUNNING  -> RUNNABLE   被抢占/主动 yield
 *   RUNNING  -> SLEEPING   等待某个事件（sleep）
 *   SLEEPING -> RUNNABLE   事件到达（wakeup）
 *   RUNNING  -> ZOMBIE     进程退出
 *   ZOMBIE   -> UNUSED     父进程 wait 回收
 */
enum proc_state {
    UNUSED,       // 未被使用
    RUNNABLE,     // 准备就绪
    RUNNING,      // 运行中
    SLEEPING,     // 睡眠等待
    ZOMBIE,       // 濒临死亡
};

// 每个进程的最大打开文件数
#define FILE_PER_PROC 128

// 前向声明
typedef struct file file_t;
typedef struct inode inode_t;

// 进程定义
typedef struct proc {

    spinlock_t lk;           // 自旋锁

    /* 下面的六个字段需要持有锁才能修改 */

    int pid;                 // 标识符
    enum proc_state state;   // 进程状态
    struct proc* parent;     // 父进程
    int exit_state;          // 进程退出时的状态(父进程可能关心)
    void* sleep_space;       // 睡眠是为在等待什么

    pgtbl_t pgtbl;           // 用户态页表，进程独有的内存空间
    uint64 heap_top;         // 用户堆顶(以字节为单位)
    uint64 ustack_pages;     // 用户栈占用的页面数量
    mmap_region_t* mmap;     // 用户可映射区域的起始节点
    trapframe_t* tf;         // 用户态内核态切换时的运行环境暂存空间，记录用户程序运行到哪里了

    uint64 kstack;           // 内核栈的虚拟地址，记录内核态代码运行到哪里了
    context_t ctx;           // 内核态进程上下文，内核处理这个进程时用的栈

    // 文件系统相关
    file_t* filelist[FILE_PER_PROC];  // 文件描述符表
    inode_t* cwd;                      // 当前工作目录
} proc_t;


void     proc_init();                                  // 进程模块初始化
void     proc_make_first();                            // 创建第一个进程并切换到它执行
pgtbl_t  proc_pgtbl_init(uint64 trapframe);            // 进程页表的初始化和基本映射
proc_t*  proc_alloc();                                 // 进程申请
void     proc_free(proc_t* p);                         // 进程释放
int      proc_fork();                                  // 复制子进程
int      proc_fork_set_usp(uint64 user_sp);            // fork 并设置子进程用户栈指针
int      proc_wait4(int64 pid, uint64 status_addr, bool status_user); // 等待子进程退出
void     proc_exit(int exit_state);                    // 进程退出
void     proc_yield();                                 // 进程放弃CPU
void     proc_sleep(void* sleep_space, spinlock_t* lk);// 进程睡眠
void     proc_wakeup(void* sleep_space);               // 进程唤醒
void     proc_sched();                                 // 进程切换到调度器
void     proc_scheduler();  

#endif

