/*
 * file.h - 打开文件（file_t）与设备抽象（dev_t）接口
 *
 * 该层位于 inode/dir 之上，为 syscall 提供“文件描述符语义”：
 *   - file_t：一次 open 后的打开实例（包含 offset、读写权限、引用计数等）
 *   - dev_t：设备文件的读写回调
 *   - ftable：内核全局打开文件表（在 file.c 中实现并用自旋锁保护）
 *
 * 额外：该实现包含一个“评测用 RAM 文件系统”用于某些测试用例。
 */
#ifndef __FILE_H__
#define __FILE_H__

#include "common.h"

// file->type 选项

#define FD_UNUSED   0
#define FD_DIR      1
#define FD_FILE     2
#define FD_DEVICE   3
#define FD_PIPE     4

// 文件打开方式 (readable writable)

#define MODE_CREATE    0x1 // 文件不存在则创建
#define MODE_READ      0x2 // 读文件
#define MODE_WRITE     0x4 // 写文件

typedef struct inode inode_t;
typedef struct pipe pipe_t;  // 前向声明

typedef struct file {
    uint16 type;      // 文件类型
    bool readable;    // 可读?
    bool writable;    // 可写?
    uint32 ref;       // 引用数
    uint16 major;     // 主设备号 (for device)
    uint32 offset;    // 偏移量   (for file)
    inode_t* ip;      // 对应的inode (for dir file device)
    pipe_t* pipe;     // 管道指针 (for pipe)
} file_t;

typedef struct file_state {
    uint16 type;
    uint16 inode_num;
    uint16 nlink;
    uint32 size;
} file_state_t;


#define N_DEV 10    // 设备类型数

#define DEV_CONSOLE 1    // 控制台的主设备号

// 设备文件需要提供读写接口
typedef struct dev {
    uint32 (*read)(uint32 len, uint64 dst, bool user_dst);
    uint32 (*write)(uint32 len, uint64 src, bool user_src);
} dev_t;


/* 初始化文件层：ftable/devlist 等。 */
void file_init();

