/*
 * inode.c - inode（索引节点）层实现
 *
 * 结构：
 *   - icache：内存 inode 缓存，提供 ref 计数与复用（受 lk_icache 保护）
 *   - inode->slk：每个 inode 的睡眠锁，保护 inode 的磁盘字段与 valid 标志
 *   - inode_rw：在磁盘 inode（按 64 字节布局）与内存 inode 之间同步
 *
 * 地址映射：
 *   - inode->addrs[] 采用“一级/二级/三级”索引，locate_block/inode_locate_block
 *     负责在需要时分配间接块并定位数据块。
 */

#include "fs/buf.h"
#include "fs/bitmap.h"
#include "fs/inode.h"
#include "fs/fs.h"
#include "mem/vmem.h"
#include "proc/cpu.h"
#include "lib/print.h"
#include "lib/str.h"

extern super_block_t sb;

// 内存中的 inode 资源 + 保护它的锁（ref 与分配/回收）。
#define N_INODE 32
static inode_t icache[N_INODE];
static spinlock_t lk_icache;

/* icache 初始化：只初始化锁，不触碰磁盘。 */
void inode_init()
{
    spinlock_init(&lk_icache, "icache");
    for(int i = 0; i < N_INODE; i++) {
        sleeplock_init(&icache[i].slk, "inode");
    }
}

/*---------------------- 与inode本身相关 -------------------*/

/*
 * 使用磁盘里的 inode 更新内存里的 inode（write=false），
 * 或使用内存里的 inode 更新磁盘里的 inode（write=true）。
 *
 * @param ip    调用者需设置 inode_num 并持有 ip->slk
 * @param write false: disk->mem; true: mem->disk
 */
void inode_rw(inode_t* ip, bool write)
{
    assert(sleeplock_holding(&ip->slk), "inode_rw: not holding lock");

    // 计算inode所在的block
    uint32 block_num = sb.inode_start + ip->inode_num / INODE_PER_BLOCK;
    buf_t* buf = buf_read(block_num);

    // 磁盘中的inode地址（每个inode 64字节）
    uint8* dip = buf->data + (ip->inode_num % INODE_PER_BLOCK) * INODE_DISK_SIZE;

    if(write) {
        // 内存 -> 磁盘
        memmove(dip, &ip->type, INODE_DISK_SIZE);
        buf_write(buf);
    } else {
        // 磁盘 -> 内存
        memmove(&ip->type, dip, INODE_DISK_SIZE);
    }
    buf_release(buf);
}

/*
 * 在 icache 里查询 inode；若不存在则分配一个空闲条目。
 *
 * @param inode_num inode 号
 * @return 返回 inode 指针（未持锁）。
 */
inode_t* inode_alloc(uint16 inode_num)
{    
    inode_t* empty = NULL;

    spinlock_acquire(&lk_icache);

    // 查找已缓存的inode
    for(int i = 0; i < N_INODE; i++) {
        if(icache[i].ref > 0 && icache[i].inode_num == inode_num) {
            icache[i].ref++;
            spinlock_release(&lk_icache);
            return &icache[i];
        }
        if(empty == NULL && icache[i].ref == 0)
            empty = &icache[i];
    }

    // 分配新的inode缓存位置
    if(empty == NULL)
        panic("inode_alloc: no free inode");

    empty->inode_num = inode_num;
    empty->ref = 1;
    empty->valid = false;

    spinlock_release(&lk_icache);
    return empty;
}

/*
 * 在磁盘里申请一个 inode，并创建其内存缓存副本。
 *
 * @return 返回 inode 指针（函数返回前已解锁）。
 */
inode_t* inode_create(uint16 type, uint16 major, uint16 minor)
{
    // 在磁盘申请inode
    uint16 inode_num = bitmap_alloc_inode();

    // 在内存申请inode
    inode_t* ip = inode_alloc(inode_num);

    // 上锁并初始化
    inode_lock(ip);
    ip->type = type;
    ip->major = major;
    ip->minor = minor;
    ip->nlink = 1;
    ip->size = 0;
    memset(ip->addrs, 0, sizeof(ip->addrs));
    ip->valid = true;

    // 写入磁盘
    inode_rw(ip, true);

    // 如果是目录，创建.和..  
    if(type == FT_DIR) {
        // 分配一个数据块
        ip->addrs[0] = bitmap_alloc_block();
        ip->size = 0;  // dir_add_entry会更新size
        inode_rw(ip, true);
    }

    inode_unlock(ip);
    return ip;
}

// 供inode_free调用
// 在磁盘上删除一个inode及其管理的文件 (修改inode bitmap + block bitmap)
// 调用者需要持有lk_icache, 但不应该持有slk
static void inode_destroy(inode_t* ip)
{
    sleeplock_acquire(&ip->slk);

    // 释放数据块
    inode_free_data(ip);

    // 清除磁盘inode
    ip->type = FT_UNUSED;
    inode_rw(ip, true);

    // 释放bitmap
    bitmap_free_inode(ip->inode_num);

    sleeplock_release(&ip->slk);
    ip->valid = false;
}

/*
 * 向 icache 里归还 inode（ref--）。
 * 当 ref==1 且 nlink==0 时，会在持有 lk_icache 的情况下触发 inode_destroy。
 */
void inode_free(inode_t* ip)
{
    spinlock_acquire(&lk_icache);

    if(ip->ref == 1 && ip->valid && ip->nlink == 0) {
        // 最后一个引用且无链接，销毁inode
        inode_destroy(ip);
    }

    ip->ref--;
    spinlock_release(&lk_icache);
}

/* ip->ref++（受 lk_icache 保护）。 */
inode_t* inode_dup(inode_t* ip)
{
    spinlock_acquire(&lk_icache);
    ip->ref++;
    spinlock_release(&lk_icache);
    return ip;
}

/*
 * 给 inode 上锁。
 * 若 ip->valid 为 false，则会从磁盘读入 inode 字段。
 */
void inode_lock(inode_t* ip)
{
    assert(ip != NULL && ip->ref > 0, "inode_lock: invalid inode");

    sleeplock_acquire(&ip->slk);

    if(ip->valid == false) {
        inode_rw(ip, false);
        ip->valid = true;
    }
}

/* 给 inode 解锁。 */
void inode_unlock(inode_t* ip)
{
    assert(ip != NULL && sleeplock_holding(&ip->slk), "inode_unlock: not holding lock");
    sleeplock_release(&ip->slk);
}

/* 组合操作：解锁 + 释放。 */
void inode_unlock_free(inode_t* ip)
{
    inode_unlock(ip);
    inode_free(ip);
}

