/*
 * buf.c - 块缓存（buffer cache）实现
 *
 * 目标：
 *   - 为上层（文件系统、EXT4 等）提供“按块读取/写回”的缓存层。
 *   - 避免重复磁盘访问，并通过每块睡眠锁保证并发安全。
 *
 * 并发/锁语义（非常重要）：
 *   - lk_buf_cache（全局自旋锁）：保护缓存元数据与 LRU 链表结构。
 *     保护字段：buf_ref、block_num、链表 next/prev 指针。
 *   - buf->slk（每块睡眠锁）：保护 buf->data[] 与 buf->disk（I/O 状态）。
 *
 * LRU 约定：
 *   - 使用一个循环双向链表；head_buf 为哨兵节点。
 *   - head_buf.next：MRU（最近释放/最近使用）的方向。
 *   - head_buf.prev：LRU（最久未用）的方向；buf_read 在这里优先找 ref==0 的可复用 buf。
 */

#include "fs/buf.h"
#include "dev/vio.h"
#include "lib/lock.h"
#include "lib/print.h"
#include "lib/str.h"

#define N_BLOCK_BUF 64
#define BLOCK_NUM_UNUSED 0xFFFFFFFF

/* 将 buf_t 包装成循环双向链表节点。
 * 说明：buf_t 是第一个成员，因此 (buf_node_t*)buf_t 指针转换是合法的。
 */
typedef struct buf_node {
    buf_t buf;
    struct buf_node* next;
    struct buf_node* prev;
} buf_node_t;

// buf cache（固定容量）。
static buf_node_t buf_cache[N_BLOCK_BUF];
// 哨兵节点：head_buf 本身不存储真实 buf，只用于简化插入/删除。
static buf_node_t head_buf;
// 保护链表结构、buf_ref、block_num 等元数据。
static spinlock_t lk_buf_cache;

/*
 * 将节点移动到链表的“头部”（MRU）或“尾部”（LRU）。
 *
 * @param bn        要移动的节点
 * @param to_mru    true：插入到 head_buf.next（MRU 方向）
 *                 false：插入到 head_buf.prev（LRU 方向）
 *
 * 约束：调用者必须持有 lk_buf_cache。
 */
static void list_move(buf_node_t* bn, bool to_mru)
{
    assert(bn != NULL, "list_move: NULL");

    // 先从原位置摘除（如果已经在链表内）。
    if (bn->next && bn->prev) {
        bn->next->prev = bn->prev;
        bn->prev->next = bn->next;
    }

    // 再插入到目标位置。
    if (to_mru) {
        // 插入到 head.next（MRU 侧）
        bn->prev = &head_buf;
        bn->next = head_buf.next;
        head_buf.next->prev = bn;
        head_buf.next = bn;
    } else {
        // 插入到 head.prev（LRU 侧）
        bn->next = &head_buf;
        bn->prev = head_buf.prev;
        head_buf.prev->next = bn;
        head_buf.prev = bn;
    }
}

// 初始化
void buf_init()
{
    spinlock_init(&lk_buf_cache, "buf_cache");

    // 初始化头节点为双向循环链表
    head_buf.next = &head_buf;
    head_buf.prev = &head_buf;

    // 将所有buf加入链表（初始都在head.prev侧，表示可分配）
    for(int i = 0; i < N_BLOCK_BUF; i++) {
        buf_cache[i].buf.block_num = BLOCK_NUM_UNUSED;
        buf_cache[i].buf.buf_ref = 0;
        sleeplock_init(&buf_cache[i].buf.slk, "buf");
        // 插入到 LRU 侧（head.prev），表示“可复用”。
        list_move(&buf_cache[i], false);
    }
}

/*
    首先假设这个block_num对应的block在内存中有备份, 找到它并上锁返回
    如果找不到, 尝试申请一个无人使用的buf, 去磁盘读取对应block并上锁返回
    如果没有空闲buf, panic报错
    (建议合并xv6的bget())
*/
/*
 * 读取 block 对应的缓存（若未缓存则从磁盘读取）。
 *
 * 核心控制流：
 *   1) 持有 lk_buf_cache 查找是否已缓存
 *   2) 命中：buf_ref++，释放 lk_buf_cache，获取 buf->slk 后返回
 *   3) 未命中：从 LRU 侧找 buf_ref==0 的 buf 复用，绑定 block_num
 *      然后释放 lk_buf_cache，获取 buf->slk，发起磁盘读
 *
 * @param block_num 磁盘块号（以 BLOCK_SIZE 为单位）
 * @return 返回已持有 buf->slk 的 buf 指针
 */
buf_t* buf_read(uint32 block_num)
{
    buf_node_t* bn;

    // block_num==BLOCK_NUM_UNUSED 属于逻辑错误：该值表示“未绑定”。
    assert(block_num != BLOCK_NUM_UNUSED, "buf_read: invalid block_num");

    spinlock_acquire(&lk_buf_cache);

    // 查找已缓存的block
    for(bn = head_buf.next; bn != &head_buf; bn = bn->next) {
        if(bn->buf.block_num == block_num) {
            bn->buf.buf_ref++;
            spinlock_release(&lk_buf_cache);
            // 睡眠锁在自旋锁之外获取，避免长时间持有自旋锁。
            sleeplock_acquire(&bn->buf.slk);
            return &bn->buf;
        }
    }

    // 未缓存，从链表尾端（LRU）找空闲buf
    for(bn = head_buf.prev; bn != &head_buf; bn = bn->prev) {
        if(bn->buf.buf_ref == 0) {
            // 复用该 buf：重新绑定 block，并标记为“正在被使用”。
            bn->buf.block_num = block_num;
            bn->buf.buf_ref = 1;
            spinlock_release(&lk_buf_cache);
            sleeplock_acquire(&bn->buf.slk);
            // 从磁盘读取
            virtio_disk_rw(&bn->buf, false);
            return &bn->buf;
        }
    }

    panic("buf_read: no free buf");
    return NULL;
}

// 写函数 (强制磁盘和内存保持一致)
void buf_write(buf_t* buf)
{
    assert(sleeplock_holding(&buf->slk), "buf_write: not holding lock");
    virtio_disk_rw(buf, true);
}

// buf 释放
void buf_release(buf_t* buf)
{
    assert(sleeplock_holding(&buf->slk), "buf_release: not holding lock");

    // 先释放睡眠锁：从这一刻起，buf->data[] 不再由当前线程独占。
    // 引用计数与 LRU 链表的更新仍需要全局自旋锁保护。

    sleeplock_release(&buf->slk);

    // 获取buf_node_t指针（buf_t是buf_node_t的第一个成员）
    buf_node_t* bn = (buf_node_t*)buf;

    spinlock_acquire(&lk_buf_cache);
    assert(bn->buf.buf_ref > 0, "buf_release: buf_ref underflow");
    bn->buf.buf_ref--;
    if(bn->buf.buf_ref == 0) {
        // ref==0 表示现在可复用：把它挪到 MRU 侧（下次更不容易被淘汰）。
        // 这是一种常见策略：越“刚用完”的 buf 越可能被再次用到。
        list_move(bn, true);
    }
    spinlock_release(&lk_buf_cache);
}

// 输出buf_cache的情况
void buf_print()
{
    printf("\nbuf_cache:\n");
    buf_node_t* buf = head_buf.next;
    spinlock_acquire(&lk_buf_cache);
    while(buf != &head_buf)
    {
        buf_t* b = &buf->buf;
        printf("buf %d: ref = %d, block_num = %d\n", (int)(buf-buf_cache), b->buf_ref, b->block_num);
        for(int i = 0; i < 8; i++)
            printf("%d ",b->data[i]);
        printf("\n");
        buf = buf->next;
    }
    spinlock_release(&lk_buf_cache);
}

/*
 * bitmap.c - 文件系统位图（bitmap）分配实现
 *
 * 该模块围绕 super_block_t 中记录的两张位图工作：
 *   - inode bitmap：分配/释放 inode 号
 *   - data bitmap：分配/释放数据区 block 号
 *
 * 实现策略：
 *   - bitmap_search_and_set() 顺序扫描一个位图 block，找到第一个 0 bit 并置 1。
 *   - bitmap_unset() 复位指定 bit。
 *
 * 并发说明：
 *   - 位图修改依赖 buf 层的锁语义与写回（buf_read/buf_write/buf_release）。
 *   - 更高层如果存在并发分配，应确保调用路径不会在同一位图上产生竞态。
 */

#include "fs/buf.h"
#include "fs/fs.h"
#include "fs/bitmap.h"
#include "lib/print.h"

extern super_block_t sb;

/*
 * 在给定的位图 block 中搜索第一个空闲 bit，并将其置 1。
 *
 * @param bitmap_block 位图所在的 block 号
 * @return 返回 bit 序号（从 0 开始）
 */
static uint32 bitmap_search_and_set(uint32 bitmap_block)
{
    uint32 byte, shift;
    uint8 bit_cmp;

    buf_t* buf = buf_read(bitmap_block);
    for(byte = 0; byte < BLOCK_SIZE; byte++) {
        bit_cmp = 1;
        for(shift = 0; shift <= 7; shift++) {
            if((bit_cmp & buf->data[byte]) == 0) {
                buf->data[byte] |= bit_cmp;
                buf_write(buf);
                buf_release(buf);
                return byte * 8 + shift;
            }
            bit_cmp = bit_cmp << 1;
        }
    }
    buf_release(buf);
    panic("bitmap_search_and_set: no bit left");
    return 0;
}

/*
 * 在给定的位图 block 中把指定 bit 复位为 0。
 *
 * @param bitmap_block 位图所在的 block 号
 * @param num         bit 序号（从 0 开始）
 */
static void bitmap_unset(uint32 bitmap_block, uint32 num)
{
    uint32 byte = num / 8;
    uint32 shift = num % 8;
    uint8 bit_cmp = 1 << shift;

    buf_t* buf = buf_read(bitmap_block);
    if((buf->data[byte] & bit_cmp) == 0)
        panic("bitmap_unset: bit already free");
    buf->data[byte] &= ~bit_cmp;
    buf_write(buf);
    buf_release(buf);
}

uint32 bitmap_alloc_block()
{
    uint32 bit_num = bitmap_search_and_set(sb.data_bitmap_start);
    return sb.data_start + bit_num;
}

void bitmap_free_block(uint32 block_num)
{
    bitmap_unset(sb.data_bitmap_start, block_num - sb.data_start);
}

uint16 bitmap_alloc_inode()
{
    return (uint16)bitmap_search_and_set(sb.inode_bitmap_start);
}

void bitmap_free_inode(uint16 inode_num)
{
    bitmap_unset(sb.inode_bitmap_start, (uint32)inode_num);
}

/*
 * 调试：打印位图中所有已分配的 bit 序号。
 *
 * @param bitmap_block_num 位图所在 block
 */
void bitmap_print(uint32 bitmap_block_num)
{
    uint8 bit_cmp;
    uint32 byte, shift;

    printf("\nbitmap:\n");

    buf_t* buf = buf_read(bitmap_block_num);
    for(byte = 0; byte < BLOCK_SIZE; byte++) {
        bit_cmp = 1;
        for(shift = 0; shift <= 7; shift++) {
            if(bit_cmp & buf->data[byte])
               printf("bit %d is alloced\n", byte * 8 + shift);
            bit_cmp = bit_cmp << 1;
        }
    }
    printf("over\n");
    buf_release(buf);
}

/*
 * elf.c - ELF64 加载器实现
 *
 * 该实现只支持最常见的静态可执行文件加载流程：
 *   - 校验 ELF 魔数、类型（ET_EXEC）、架构（EM_RISCV）
 *   - 遍历程序头（Program Header），对每个 PT_LOAD 段：
 *       1) 按页分配物理页并映射到用户页表
 *       2) 从 elf_data 拷贝文件内容（filesz），其余 memsz 区域保持为 0（BSS）
 *   - 输出入口地址 e_entry 与 heap_top（最高段末尾按页对齐）
 */

#include "fs/elf.h"
#include "mem/vmem.h"
#include "mem/pmem.h"
#include "lib/str.h"
#include "lib/print.h"
#include "memlayout.h"

#ifdef ELF_DEBUG
#define ELF_LOG printf
#else
#define ELF_LOG(...) do { } while (0)
#endif

/* 加载 ELF 文件到用户页表。具体参数说明见 include/fs/elf.h。 */
int elf_load(void* elf_data, uint32 elf_size, 
             void* pgtbl, uint64* entry_out, uint64* heap_top_out)
{
    elf64_ehdr_t* ehdr = (elf64_ehdr_t*)elf_data;

    // 验证ELF魔数
    if (!elf_check_magic(ehdr)) {
        ELF_LOG("[ELF] Invalid ELF magic\n");
        return -1;
    }

    // 验证是可执行文件
    if (ehdr->e_type != ET_EXEC) {
        ELF_LOG("[ELF] Not an executable file (type=%d)\n", ehdr->e_type);
        return -1;
    }

    // 验证是RISC-V架构
    if (ehdr->e_machine != EM_RISCV) {
        ELF_LOG("[ELF] Not RISC-V architecture (machine=%d)\n", ehdr->e_machine);
        return -1;
    }

    // 验证程序头
    if (ehdr->e_phnum == 0) {
        ELF_LOG("[ELF] No program headers\n");
        return -1;
    }

    // 验证程序头数量
    if (ehdr->e_phnum == 0 || ehdr->e_phnum > 128) {
        ELF_LOG("[ELF] Invalid phnum: %d\n", ehdr->e_phnum);
        return -1;
    }

    ELF_LOG("[ELF] Loading ELF: entry=0x%p, phnum=%d\n", 
            ehdr->e_entry, ehdr->e_phnum);

    pgtbl_t user_pgtbl = (pgtbl_t)pgtbl;
    uint64 max_vaddr = 0;

    // 遍历程序头，加载PT_LOAD段
    uint8* phdr_base = (uint8*)elf_data + ehdr->e_phoff;

    for (int i = 0; i < ehdr->e_phnum; i++) {
        elf64_phdr_t* phdr = (elf64_phdr_t*)(phdr_base + i * ehdr->e_phentsize);

        // 只处理可加载段
        if (phdr->p_type != PT_LOAD) {
            continue;
        }

        // 跳过大小为0的段
        if (phdr->p_memsz == 0) {
            continue;
        }

        ELF_LOG("[ELF] Loading segment %d: vaddr=0x%lx, filesz=0x%lx, memsz=0x%lx\n",
            i, phdr->p_vaddr, phdr->p_filesz, phdr->p_memsz);

        // 计算权限
        uint64 perm = PTE_U;  // 用户可访问
        if (phdr->p_flags & PF_R) perm |= PTE_R;
        if (phdr->p_flags & PF_W) perm |= PTE_W;
        if (phdr->p_flags & PF_X) perm |= PTE_X;

        // 按页分配并映射
        uint64 va_start = ALIGN_DOWN(phdr->p_vaddr, PGSIZE);
        uint64 va_end = ALIGN_UP(phdr->p_vaddr + phdr->p_memsz, PGSIZE);

        for (uint64 va = va_start; va < va_end; va += PGSIZE) {
            // 分配物理页
            uint64 pa = (uint64)pmem_alloc(false);
            if (pa == 0) {
                ELF_LOG("[ELF] Failed to allocate page\n");
                return -1;
            }
            memset((void*)pa, 0, PGSIZE);

            // 映射页面
            vm_mappages(user_pgtbl, va, pa, PGSIZE, perm);

            // 如果在文件范围内，复制数据
            uint64 seg_offset = va - phdr->p_vaddr;
            if (seg_offset < phdr->p_filesz) {
                uint64 file_offset = phdr->p_offset + seg_offset;
                uint64 copy_start = (va < phdr->p_vaddr) ? 
                                    (phdr->p_vaddr - va) : 0;
                uint64 copy_end = PGSIZE;

                // 计算实际复制量
                uint64 remain_file = phdr->p_filesz - seg_offset;
                if (remain_file < PGSIZE - copy_start) {
                    copy_end = copy_start + remain_file;
                }

                if (copy_end > copy_start && file_offset < elf_size) {
                    uint64 len = copy_end - copy_start;
                    if (file_offset + len > elf_size) {
                        len = elf_size - file_offset;
                    }
                    memmove((void*)(pa + copy_start), 
                            (uint8*)elf_data + file_offset, len);
                }
            }
        }

        // 更新最高虚拟地址
        if (va_end > max_vaddr) {
            max_vaddr = va_end;
        }
    }

    // 设置输出参数
    *entry_out = ehdr->e_entry;
    *heap_top_out = ALIGN_UP(max_vaddr, PGSIZE);

        ELF_LOG("[ELF] Loaded successfully: entry=0x%p, heap_top=0x%p\n",
            *entry_out, *heap_top_out);

    return 0;
}

#include <stdarg.h>
#include "lib/print.h"
#include "lib/lock.h"
#include "dev/uart.h"

// 系统崩溃标志（volatile保证多核可见）
volatile int panicked = 0;

static spinlock_t print_lk;
static char digits[] = "0123456789abcdef";

void print_init(void)
{
    spinlock_init(&print_lk, "print");
}

// 打印整数（支持不同进制和符号）
static void printint(long long xx, int base, int sign)
{
    char buf[20];
    int i;
    unsigned long long x;
    // sign = 1表示需要考虑符号
    if (sign && (sign = (xx < 0)))
        x = -xx;
    else
        x = xx;

    i = 0;
    do {
        buf[i++] = digits[x % base];
    } while ((x /= base) != 0);

    if (sign)
        buf[i++] = '-';

    while (--i >= 0)
        uart_putc_sync(buf[i]);
}

// 打印指针（16进制，带0x前缀）
static void printptr(unsigned long long x)
{
    uart_putc_sync('0');
    uart_putc_sync('x');
    for (int i = 0; i < 16; i++, x <<= 4)
        uart_putc_sync(digits[x >> 60]);
}

// 主要的 printf 实现
void printf(const char *fmt, ...)
{
    va_list ap;
    int i, c;
    char *s;

    spinlock_acquire(&print_lk);  // 获取锁，防止输出交错
    /*这是一个防御性编程习惯。char 在某些机器上是有符号的。
    如果不加这个，如果字符编码超过 127，可能会被当成负数处理，导致意外错误。
    这里强制把它看作 0-255 的无符号数*/
    va_start(ap, fmt);
    for (i = 0; (c = fmt[i] & 0xff) != 0; i++) {
        if (c != '%') {
            uart_putc_sync(c);
            continue;
        }
        c = fmt[++i] & 0xff;
        if (c == 0)
            break;
        switch (c) {
        case 'd':
            printint(va_arg(ap, int), 10, 1);
            break;
        case 'x':
            printint(va_arg(ap, int), 16, 0);
            break;
        case 'p':
            printptr(va_arg(ap, unsigned long long));
            break;
        case 's':
            if ((s = va_arg(ap, char*)) == 0)
                s = "(null)";
            for (; *s; s++)
                uart_putc_sync(*s);
            break;
        case '%':
            uart_putc_sync('%');
            break;
        default:
            uart_putc_sync('%');
            uart_putc_sync(c);
            break;
        }
    }
    va_end(ap);

    spinlock_release(&print_lk);  // 释放锁
}

void panic(const char *s)
{
    panicked = 1;
    printf("panic: %s\n", s);
    while (1)
        ;
}

void assert(bool condition, const char* warning)
{
    if (!condition) {
        panic(warning);
    }
}

/*
 * spinlock.c - 自旋锁与可嵌套的关/开中断
 *
 * 这份实现的核心思路：
 *   - 获取自旋锁前先关闭中断，避免：
 *     1) 持锁期间被中断打断，中断处理路径再次尝试获取同一把锁导致死锁；
 *     2) 在同一 CPU 上发生不可控的重入。
 *   - push_off/pop_off 支持嵌套：多个层级都可以“确保中断关闭”，最后一层再恢复。
 */

#include "lib/lock.h"
#include "lib/print.h"
#include "proc/proc.h"
#include "proc/cpu.h"
#include "riscv.h"

/*
 * push_off - 可嵌套地关闭中断。
 *
 * 行为：
 *   - 读取当前中断开关 old
 *   - 关闭中断
 *   - 若这是当前 CPU 第一次 push_off，则记录 old 供最终恢复
 *   - noff++ 记录嵌套深度
 */
void push_off(void)
{
    int old = intr_get();  // 获取当前中断状态
    intr_off();            // 关中断,设置sstatus寄存器的SSTATUS_SIE位为0

    cpu_t* c = mycpu();
    if (c->noff == 0) {
        c->origin = old;   // 记录原始状态，只有第一次关中断时才记录
    }
    c->noff++;             // 嵌套层数+1
}

/*
 * pop_off - 可嵌套地恢复中断。
 *
 * 只有当：
 *   - noff 递减到 0
 *   - 且 origin 记录的是“原本开中断”
 * 才会真正调用 intr_on()。
 */
void pop_off(void)
{
    cpu_t* c = mycpu();

    // 约束：pop_off 时必须处于“中断已关闭”的状态，否则说明 push/pop 不匹配或被错误开启。
    if (intr_get()) {
        panic("pop_off - interruptible");
    }
    // noff < 1 说明没有对应的 push_off。
    if (c->noff < 1) {
        panic("pop_off");
    }

    c->noff--;
    if (c->noff == 0 && c->origin) {
        intr_on();         // 恢复中断
    }
    // 只有当所有嵌套都结束且原始状态为开中断时才真正开中断。
}

// 检查当前 CPU 是否持有锁（调试/断言）。
bool spinlock_holding(spinlock_t *lk)
{
    return (lk->locked && lk->cpuid == mycpuid());
}

// 初始化自旋锁
void spinlock_init(spinlock_t *lk, char *name)
{
    lk->name = name;
    lk->locked = 0;
    lk->cpuid = -1;
}

// 获取自旋锁：忙等直到将 locked 从 0 原子置为 1。
void spinlock_acquire(spinlock_t *lk)
{    
    push_off();  // 关中断

    if (spinlock_holding(lk)) {
        panic("spinlock_acquire");
    }

    // 原子操作：test-and-set。循环直到成功将 locked 从 0 设为 1。
    while (__sync_lock_test_and_set(&lk->locked, 1) != 0)
        ;

    // 内存屏障：确保临界区内的读写不会被编译器/CPU 乱序到加锁之前。
    __sync_synchronize();
    lk->cpuid = mycpuid();
} 

// 释放自旋锁
void spinlock_release(spinlock_t *lk)
{
    if (!spinlock_holding(lk)) {
        panic("spinlock_release");
    }

    lk->cpuid = -1;
    // 内存屏障：确保临界区内的写入在解锁前对其他 CPU 可见。
    __sync_synchronize();
    __sync_lock_release(&lk->locked);  // 原子释放

    pop_off();  // 恢复中断
}

/*
 * sleeplock.c - 睡眠锁（可能阻塞/让出 CPU 的互斥）
 *
 * 适用场景：临界区可能较长，或会等待 I/O。
 *   - 自旋锁：忙等，不允许睡眠；适合极短临界区。
 *   - 睡眠锁：当锁被占用时，睡眠等待被唤醒后再竞争；适合长临界区。
 *
 * 实现要点：
 *   - sleeplock 的状态字段由内部自旋锁 lk->lk 保护。
 *   - 早期启动阶段可能没有当前进程（myproc() == NULL），无法睡眠/调度，
 *     这里退化为自旋等待以保证内核初始化过程可用。
 *   - pid 记录持锁者：有进程时记录进程 pid；无进程阶段使用 -1 作为哨兵值。
 */

#include "lib/lock.h"
#include "proc/proc.h"
#include "proc/cpu.h"

// 初始化睡眠锁。
void sleeplock_init(sleeplock_t* lk, char* name)
{
    spinlock_init(&lk->lk, "sleeplock");
    lk->name = name;
    lk->locked = 0;
    lk->pid = 0;
}

// 获取睡眠锁：若被占用则睡眠等待（早期阶段退化为自旋等待）。
void sleeplock_acquire(sleeplock_t* lk)
{
    spinlock_acquire(&lk->lk);

    // 在没有进程的情况下（内核初始化阶段），使用自旋等待。
    proc_t* p = myproc();
    while(lk->locked) {
        if(p != NULL) {
            // 有进程：阻塞等待。proc_sleep 会在睡眠前原子释放 lk->lk，避免竞态。
            proc_sleep(lk, &lk->lk);
        } else {
            // 无进程时自旋等待
            spinlock_release(&lk->lk);
            spinlock_acquire(&lk->lk);
        }
    }
    lk->locked = 1;
    // 记录持锁者，便于调试/holding() 检查。
    lk->pid = (p != NULL) ? p->pid : -1;
    spinlock_release(&lk->lk);
}

// 释放睡眠锁，并唤醒等待者。
void sleeplock_release(sleeplock_t* lk)
{
    spinlock_acquire(&lk->lk);
    lk->locked = 0;
    lk->pid = 0;
    // 唤醒所有等待在该 channel（这里就是 lk 指针）上的进程。
    proc_wakeup(lk);
    spinlock_release(&lk->lk);
}

// 检查当前执行上下文是否持有睡眠锁。
bool sleeplock_holding(sleeplock_t* lk)
{
    int r;
    spinlock_acquire(&lk->lk);
    proc_t* p = myproc();
    if(p != NULL) {
        r = lk->locked && (lk->pid == p->pid);
    } else {
        // 早期无进程阶段：用 pid=-1 表示“内核初始化上下文持锁”。
        r = lk->locked && (lk->pid == -1);
    }
    spinlock_release(&lk->lk);
    return r;
}

uint64 sys_write(void)
{
