// QEMU virt机器的TEST设备地址
// 这个设备用于测试，写入特定值可以关机
#define VIRT_TEST_ADDR   0x100000ul
#define VIRT_TEST_FINISHER_PASS  0x5555
#define VIRT_TEST_FINISHER_FAIL  0x3333

// 关机函数
void poweroff(void)
{
    printf("\n[POWEROFF] System halting...\n");

    // 写入关机命令
    volatile uint32* test = (volatile uint32*)VIRT_TEST_ADDR;
    *test = VIRT_TEST_FINISHER_PASS;

    // 如果上面没有生效，进入死循环（等待中断，避免忙等）。
    while(1) {
        asm volatile("wfi");
    }
}

