uint64 sys_pipe2(void)
{
    uint64 pipefd_addr;
    uint64 flags;
    arg_uint64(0, &pipefd_addr);
    arg_uint64(1, &flags);

    proc_t* p = myproc();

    // 初始化管道锁
    if (!pipe_lock_init) {
        spinlock_init(&pipe_lock, "pipe");
        for (int i = 0; i < 8; i++) {
            spinlock_init(&pipes[i].lock, "pipe_data");
        }
        pipe_lock_init = 1;
    }

    // 分配管道
    spinlock_acquire(&pipe_lock);
    int pi = -1;
    for (int i = 0; i < 8; i++) {
        if (!pipe_used[i]) {
            pi = i;
            pipe_used[i] = 1;
            break;
        }
    }
    spinlock_release(&pipe_lock);

    if (pi < 0) {
        return -1;  // 没有可用管道
    }

    pipe_t* pp = &pipes[pi];
    pp->nread = 0;
    pp->nwrite = 0;
    pp->readopen = 1;
    pp->writeopen = 1;

    // 分配读端和写端的file
    file_t* rf = file_alloc();
    file_t* wf = file_alloc();

    if (rf == NULL || wf == NULL) {
        if (rf) file_close(rf);
        if (wf) file_close(wf);
        pipe_used[pi] = 0;
        return -1;
    }

    rf->type = FD_PIPE;
    rf->readable = true;
    rf->writable = false;
    rf->pipe = pp;

    wf->type = FD_PIPE;
    wf->readable = false;
    wf->writable = true;
    wf->pipe = pp;

    // 分配文件描述符
    int rfd = fd_alloc(rf);
    int wfd = fd_alloc(wf);

    if (rfd < 0 || wfd < 0) {
        if (rfd >= 0) { p->filelist[rfd] = NULL; }
        if (wfd >= 0) { p->filelist[wfd] = NULL; }
        file_close(rf);
        file_close(wf);
        pipe_used[pi] = 0;
        return -1;
    }

    // 将fd写回用户空间
    int fds[2] = {rfd, wfd};
    uvm_copyout(p->pgtbl, pipefd_addr, (uint64)fds, sizeof(fds));

    return 0;
}

// Linux getdents64 目录项结构
struct linux_dirent64 {
    uint64 d_ino;     // inode号
    uint64 d_off;     // 下一个目录项的偏移
    uint16 d_reclen;  // 本条记录长度
    uint8  d_type;    // 文件类型
