/*
 * inode.h - inode（索引节点）层接口
 *
 * inode 是文件系统中对“文件/目录/设备”的统一抽象：
 *   - 磁盘中的 inode 记录：type/size/addrs 等（由 inode->slk 保护）
 *   - 内存中的 inode 缓存（icache）：提供 ref 计数与复用（由 lk_icache 保护）
 *
 * 重要并发约定：
 *   - inode_alloc/inode_dup/inode_free 只管理 ref，与 icache 锁有关；
 *   - inode_lock/inode_unlock 管理 inode 的睡眠锁 slk，并负责延迟加载 valid 字段；
 *   - 读写 inode 管理的数据（inode_read_data/inode_write_data/...）必须持有 slk。
 */
#ifndef __INODE_H__
#define __INODE_H__

#include "lib/lock.h"

#define INODE_ROOT       0                              // 根节点的inode_num
#define INODE_DISK_SIZE  64                             // 磁盘里inode的大小
#define INODE_PER_BLOCK  (BLOCK_SIZE / INODE_DISK_SIZE) // 每个block里的inode数量

// addrs相关字段
#define N_ADDRS_1   10  // 管理 10 * BLOCK_SIZE = 10KB
#define N_ADDRS_2   2   // 管理 2 * (BLOCK_SIZE / 4) * BLOCK_SIZE = 512KB
#define N_ADDRS_3   1   // 管理 (BLOCK_SIZE / 4) * (BLOCK_SIZE / 4) * BLOCK_SIZE = 64MB
#define N_ADDRS     (N_ADDRS_1 + N_ADDRS_2 + N_ADDRS_3)

// 每个block里面有多少个存储下一级block_num的entry
#define ENTRY_PER_BLOCK (BLOCK_SIZE / sizeof(uint32))

// addrs字段可以容纳的最大空间（单个inode可以管理的最大空间）
// 由于磁盘大小限制, 事实上达不到这个大小
#define INODE_MAXSIZE ((N_ADDRS_1 + N_ADDRS_2 * ENTRY_PER_BLOCK + N_ADDRS_3 * ENTRY_PER_BLOCK * ENTRY_PER_BLOCK) * BLOCK_SIZE)

// type 选项
#define FT_UNUSED 0
#define FT_DIR    1
#define FT_FILE   2
#define FT_DEVICE 3

// inode_num 无效的inode号
#define INODE_NUM_UNUSED 0xFFFF

typedef struct inode {
    // 磁盘里的inode信息 (由slk保护)
    uint16 type;                // inode 管理的文件类型
    uint16 major;               // 设备文件使用: 主设备号
    uint16 minor;               // 设备文件使用: 次设备号
    uint16 nlink;               // 链接数量 (nlink个文件名链接到这个inode)
    uint32 size;                // 文件大小 (字节)
    uint32 addrs[N_ADDRS];      // 文件存储在哪些block里 (分为一级 二级 三级)

    // 内存里的inode信息
    uint16 inode_num;           // inode序号
    uint32 ref;                 // 引用数 (由lk_icache保护)
    bool valid;                 // 上述磁盘里inode字段的有效性 (由slk保护)
    sleeplock_t slk;            // 睡眠锁

} inode_t;

/*---------------------------- inode 元数据（metadata） ----------------------------*/

/* 初始化 inode 缓存（icache）。只需启动时调用一次。 */
void inode_init();

/*
 * 在“磁盘 inode”与“内存 inode”之间同步。
 *
 * @param ip    inode（调用者需已设置 inode_num，并持有 ip->slk）
 * @param write false：磁盘 -> 内存；true：内存 -> 磁盘
 */
void inode_rw(inode_t* ip, bool write);

/*
 * 在 icache 中查找/分配一个 inode（ref++）。
 *
 * @param inode_num inode 号
 * @return 返回 inode 指针（未持锁）。
 */
inode_t* inode_alloc(uint16 inode_num);

/*
 * 在磁盘中创建一个新的 inode，并在内存中分配对应缓存项。
 *
 * @param type  文件类型（FT_DIR/FT_FILE/FT_DEVICE）
 * @param major 设备主设备号（仅 FT_DEVICE 有意义）
 * @param minor 设备次设备号（仅 FT_DEVICE 有意义）
 * @return 成功返回 inode 指针（未持锁）；失败返回 NULL。
 */
inode_t* inode_create(uint16 type, uint16 major, uint16 minor);

/*
 * 释放 inode 引用（ref--）。当 ref==0 且 nlink==0 时，会触发真正销毁。
 *
 * @param ip inode（调用者不应持有 ip->slk）
 */
void inode_free(inode_t* ip);

/* 增加 inode 引用计数（ref++）。 */
inode_t* inode_dup(inode_t* ip);

/*
 * 获取 inode 的睡眠锁；若 ip->valid 为 false，会从磁盘读入 inode 字段。
 *
 * @param ip inode（必须非空，且 ref>0）
 */
void inode_lock(inode_t* ip);

/* 释放 inode 的睡眠锁。 */
void inode_unlock(inode_t* ip);

/* 组合操作：inode_unlock(ip) + inode_free(ip)。 */
void inode_unlock_free(inode_t* ip);

/*---------------------------- inode 管理的数据（data blocks） ----------------------------*/

/*
 * 从 inode 对应文件读取数据。
 *
 * @param ip     inode（调用者需持有 ip->slk）
 * @param offset 文件内偏移（字节）
 * @param len    期望读取长度
 * @param dst    目标地址（内核或用户空间）
 * @param user   dst 是否为用户地址
 * @return 实际读取字节数。
 */
uint32 inode_read_data(inode_t* ip, uint32 offset, uint32 len, void* dst, bool user);

/*
 * 向 inode 对应文件写入数据。
 *
 * @param ip     inode（调用者需持有 ip->slk）
 * @param offset 文件内偏移（字节）
 * @param len    期望写入长度
 * @param src    源地址（内核或用户空间）
 * @param user   src 是否为用户地址
 * @return 实际写入字节数。
 */
uint32 inode_write_data(inode_t* ip, uint32 offset, uint32 len, void* src, bool user);

/*
 * 释放 inode 管理的所有数据块，并清空 addrs/size。
 *
 * @param ip inode（调用者需持有 ip->slk）
 */
void inode_free_data(inode_t* ip);

/* 调试：打印 inode 的关键字段。调用者需持有 ip->slk。 */
void inode_print(inode_t* ip);

#endif
